window.QUIZ_DATA = {"version": 2, "topics": {"t1": "Тема 1. Введение в ИНС", "t2": "Тема 2. Обратное распространение", "t3": "Тема 3. Обучение ИНС и ГНС", "t4": "Тема 4. Свёрточные сети (СНС)", "t5": "Тема 5. Рекуррентные сети (РНС)", "t6": "Тема 6. Трансформеры", "t7": "Тема 7. Предположительный тест с github"}, "questions": [{"id": "t1-001", "topic": "t1", "q": "Что такое искусственная нейронная сеть (ИНС) согласно определению из курса?", "a": ["Параметрическая функция отображения входов в выходы", "Алгоритм точного поиска в графе состояний", "База правил «если–то» экспертной системы", "Метод решения систем линейных уравнений"], "correct": 0, "explanation": "ИНС определяется как параметрически заданная функция, отображающая входные сигналы в выходные с помощью модели из связанных формальных нейронов."}, {"id": "t1-002", "topic": "t1", "q": "Какими двумя словами в курсе характеризуется основная тенденция развития кибернетики начала третьего тысячелетия?", "a": ["Биологизация и гибридизация", "Цифровизация и виртуализация", "Линеаризация и дискретизация", "Кластеризация и регуляризация"], "correct": 0, "explanation": "Лекция 1: тенденция — биологизация (имитация природных механизмов) и гибридизация (сочетание разных подходов)."}, {"id": "t1-003", "topic": "t1", "q": "Что вычисляет адаптивный сумматор формального нейрона?", "a": ["Скалярное произведение входов и весов", "Векторное произведение входных сигналов", "Сумму модулей входных сигналов", "Евклидову норму входного вектора"], "correct": 0, "explanation": "Адаптивный сумматор складывает взвешенные входы алгебраически: s = wᵀx. «Адаптивным» назван из-за наличия настраиваемых параметров."}, {"id": "t1-004", "topic": "t1", "q": "Из каких трёх элементов составлен стандартный формальный нейрон?", "a": ["Сумматор, нелинейность, точка ветвления", "Блок памяти, регистр и шина данных", "Свёртка, пулинг и функция softmax", "Кодер, декодер и механизм внимания"], "correct": 0, "explanation": "Формальный нейрон = адаптивный (входной) сумматор + нелинейная активационная функция + точка ветвления для рассылки выхода."}, {"id": "t1-005", "topic": "t1", "q": "Какое из требований обычно НЕ предъявляется к активационной функции нейрона?", "a": ["Строгая выпуклость на всей области", "Монотонное возрастание функции", "Производная существует почти всюду", "Производная выражается через саму функцию"], "correct": 0, "explanation": "Требуются монотонность, существование производной почти всюду и удобное выражение производной через саму функцию. Выпуклость не требуется."}, {"id": "t1-006", "topic": "t1", "q": "Как задаётся функция активации ReLU?", "a": ["f(s)=s при s>0, иначе f(s)=0", "f(s)=1/(1+e^{−s}) (сигмоида)", "f(s)=tanh(s) (тангенс)", "f(s)=s² при любом значении s"], "correct": 0, "explanation": "ReLU (Rectified Linear Unit) пропускает положительные значения без изменений и обнуляет отрицательные."}, {"id": "t1-007", "topic": "t1", "q": "Чем Leaky ReLU отличается от обычного ReLU?", "a": ["При s<0 даёт малый наклон 0.01·s", "Возводит входной сигнал в квадрат", "Ограничивает выход сверху единицей", "Применяет softmax к выходу нейрона"], "correct": 0, "explanation": "Leaky ReLU при отрицательном аргументе даёт небольшой ненулевой наклон (0.01·s), что снижает проблему «мёртвых» нейронов."}, {"id": "t1-008", "topic": "t1", "q": "Какую функцию активации также называют функцией Ферми?", "a": ["Логистическую сигмоиду 1/(1+e^{−s})", "Выпрямитель ReLU max(0,s)", "Гиперболический тангенс tanh(s)", "Знаковую функцию sign(s)"], "correct": 0, "explanation": "Логистическая функция 1/(1+e^{-s}) в курсе называется функцией Ферми."}, {"id": "t1-009", "topic": "t1", "q": "На какие две базовые группы делят архитектуры ИНС в курсе?", "a": ["Слоистые и полносвязные сети", "Линейные и квадратичные сети", "Кодеры и декодеры сигналов", "Свёрточные и пулинговые сети"], "correct": 0, "explanation": "Базовое деление: слоистые (многослойные) и полносвязные сети; отдельно рассматривают смешанный вариант — рекуррентные."}, {"id": "t1-010", "topic": "t1", "q": "Какую сеть называют однородной (гомогенной)?", "a": ["Активация одинакова во всех нейронах", "Все весовые коэффициенты равны нулю", "В сети полностью отсутствуют слои", "Все слои имеют одинаковый размер"], "correct": 0, "explanation": "Если активационная функция одинакова во всех нейронах — сеть однородная; если f зависит от меняющихся параметров — неоднородная (гетерогенная)."}, {"id": "t1-011", "topic": "t1", "q": "Как в курсе определяется рекуррентная сеть в общем случае?", "a": ["Любая ИНС, имеющая обратные связи", "Сеть только из свёрточных слоёв", "Сеть без активационных функций", "Сеть, обучаемая всегда без учителя"], "correct": 0, "explanation": "В общем случае рекуррентная — любая ИНС с обратными связями. На практике под РНС часто понимают слоистую сеть с обратными связями между слоями."}, {"id": "t1-012", "topic": "t1", "q": "Как называют три слоя в распространённой трёхслойной сети?", "a": ["Входной, скрытый, выходной", "Свёрточный, пулинг, плотный", "Кодер, латентный, декодер", "Прямой, обратный, агрегирующий"], "correct": 0, "explanation": "В трёхслойной сети слои называют: первый — входной, второй — скрытый, третий — выходной."}, {"id": "t1-013", "topic": "t1", "q": "О чём говорит теорема Колмогорова–Арнольда (1957)?", "a": ["Функция n переменных — суперпозиция функций одной", "Любая функция бесконечно дифференцируема", "Градиентный спуск даёт глобальный минимум", "Число параметров не влияет на качество"], "correct": 0, "explanation": "Теорема Колмогорова–Арнольда: непрерывную функцию n переменных можно представить через суммы и суперпозиции функций одной переменной — обоснование 3-слойной архитектуры."}, {"id": "t1-014", "topic": "t1", "q": "Почему в курсе особенно популярны именно трёхслойные сети?", "a": ["Теорема Колмогорова доказывает их достаточность", "Три слоя всегда обучаются быстрее прочих", "Больше трёх слоёв реализовать невозможно", "Три слоя не требуют функций активации"], "correct": 0, "explanation": "Теорема Колмогорова указывает архитектуру (3 слоя) и минимальное число нейронов, точно представляющую функцию, — отсюда популярность 3-слойных сетей."}, {"id": "t1-015", "topic": "t1", "q": "Что утверждает аппроксимационная теорема Вейерштрасса (1885)?", "a": ["Непрерывную функцию равномерно приближают полиномы", "Любую функцию точно задаёт один нейрон", "Полиномы не способны приближать синус", "Сходимость в среднем равна равномерной"], "correct": 0, "explanation": "Теорема Вейерштрасса: множество многочленов плотно в множестве непрерывных функций на компакте — их можно равномерно приблизить."}, {"id": "t1-016", "topic": "t1", "q": "Что устанавливает теорема Стоуна (1935) применительно к ИНС?", "a": ["Подалгебра с единицей, разделяющая точки, плотна", "Нейросети не приближают непрерывные функции", "Любая алгебра топологически замкнута", "Производная суммы равна сумме производных"], "correct": 0, "explanation": "Теорема Стоуна обобщает Вейерштрасса: класс функций, замкнутый относительно операций, содержащий единицу и разделяющий точки, плотен в C(X). Класс функций ИНС этим условиям удовлетворяет."}, {"id": "t1-017", "topic": "t1", "q": "Что такое компакт в контексте теорем существования?", "a": ["Замкнутое и ограниченное множество", "Множество из конечного числа точек", "Любое открытое множество в R", "Множество без предельных точек"], "correct": 0, "explanation": "Компакт — обобщение замкнутых и ограниченных множеств. Множество ограничено (конечный диаметр) и замкнуто (содержит все предельные точки)."}, {"id": "t1-018", "topic": "t1", "q": "Какое свойство означает, что функция «разделяет точки» в пространстве X?", "a": ["Для любых x≠y значения f(x)≠f(y)", "f(x)=0 для всех точек x", "Функция f монотонно возрастает", "Функция f ограничена сверху и снизу"], "correct": 0, "explanation": "Функция разделяет точки, если для любых различных x и y значения функции различны: f(x)≠f(y)."}, {"id": "t1-019", "topic": "t1", "q": "Чем полносвязная сеть принципиально отличается от слоистой при неограниченном числе тактов?", "a": ["Слоистая не работает, полносвязная — да", "Полносвязная сеть не содержит весов", "Слоистая сеть оказывается всегда точнее", "Между ними нет никаких различий"], "correct": 0, "explanation": "Когда число тактов заранее не ограничено, слоистая сеть работать не может; полносвязная же пересчитывает сигналы от такта к такту до получения ответа."}, {"id": "t1-020", "topic": "t1", "q": "Кто и в каком десятилетии разработал перцептрон (однослойную сеть), согласно лекциям?", "a": ["Маккалок и Питтс (1940-е), Розенблатт (1960-е)", "Джеффри Хинтон в 1990-х годах", "Владимир Вапник в 1970-х годах", "Ашиш Васвани и др. в 2017 году"], "correct": 0, "explanation": "Перцептрон описан Маккалоком и Питтсом в 40-х; основные результаты о его возможностях получил Ф. Розенблатт в 60-х («Принципы нейродинамики», 1965)."}, {"id": "t1-021", "topic": "t1", "q": "Что показал Розенблатт о возможностях перцептрона?", "a": ["Может научиться всему, что способен представить", "Решает любую задачу вообще без обучения", "Не нуждается в настраиваемых весах", "Всегда переобучается на любых данных"], "correct": 0, "explanation": "Розенблатт показал: если перцептрон в состоянии безошибочно решать задачу, то он способен обучиться так, чтобы её решать."}, {"id": "t1-022", "topic": "t1", "q": "Что такое точка ветвления в формальном нейроне?", "a": ["Рассылает выход нейрона на входы других", "Суммирует взвешенные входные сигналы", "Выполняет нелинейное преобразование", "Хранит настраиваемые веса нейрона"], "correct": 0, "explanation": "Точка ветвления получает скалярный выход y и передаёт его всем выходам — рассылает сигнал по другим нейронам сети."}, {"id": "t1-023", "topic": "t1", "q": "Что в формальном нейроне играет роль, аналогичную «синаптической силе» биологической связи?", "a": ["Весовые коэффициенты wᵢ", "Функция активации f(s)", "Только смещение нейрона b", "Число слоёв в сети"], "correct": 0, "explanation": "Каждый входной сигнал умножается на вес wᵢ — аналог «синаптической силы» биологической связи."}, {"id": "t1-024", "topic": "t1", "q": "Под биологизацией в кибернетике в курсе понимают:", "a": ["Имитацию механизмов живой природы в моделях", "Замену компьютеров биологическими тканями", "Полный запрет на использование математики", "Сбор биологических данных для статистики"], "correct": 0, "explanation": "Биологизация — построение и исследование моделей сложных объектов на основе имитации природных механизмов (нечёткая логика, ИНС, роевые методы и т.п.)."}, {"id": "t1-025", "topic": "t1", "q": "Что означает, что алгебра «содержит единицу»?", "a": ["Есть элемент, нейтральный к её операции", "В множестве присутствует число 1", "Все элементы множества равны единице", "Алгебра состоит из одного элемента"], "correct": 0, "explanation": "Алгебра содержит единицу, когда существует элемент множества, нейтральный по отношению к операции алгебры (для нейросети — единичная сеть)."}, {"id": "t1-026", "topic": "t1", "q": "Что в формальном нейроне является аналогом тела биологического нейрона (сомы)?", "a": ["Адаптивный сумматор (блок суммирования)", "Точка ветвления выходного сигнала", "Отдельный весовой коэффициент", "Только функция активации нейрона"], "correct": 0, "explanation": "Адаптивный сумматор играет роль тела нейрона: он алгебраически складывает взвешенные входы, как сома интегрирует поступающие сигналы."}, {"id": "t1-027", "topic": "t1", "q": "Что в искусственном нейроне соответствует биологическому аксону?", "a": ["Точка ветвления, рассылающая выход", "Входной адаптивный сумматор", "Вектор синаптических весов", "Смещение (свободный член)"], "correct": 0, "explanation": "Точка ветвления получает выходной сигнал и передаёт его дальше — это функциональный аналог аксона, передающего сигнал другим нейронам."}, {"id": "t1-028", "topic": "t1", "q": "Почему нелинейность активационной функции принципиально важна для многослойной сети?", "a": ["Иначе все слои сводятся к одному линейному", "Она ускоряет матричное умножение", "Она убирает потребность в весах", "Она нужна только входному слою"], "correct": 0, "explanation": "Суперпозиция линейных слоёв снова линейна; без нелинейной активации глубокая сеть эквивалентна одному линейному слою и не может выражать сложные функции."}, {"id": "t1-029", "topic": "t1", "q": "Что такое неоднородный адаптивный сумматор?", "a": ["Сумматор со смещением w₀", "Сумматор без весовых коэффициентов", "Сумматор с нелинейностью внутри", "Сумматор из двух нейронов сразу"], "correct": 0, "explanation": "Неоднородный сумматор добавляет к взвешенной сумме входов смещение w₀ (bias): s = w₀ + Σ wᵢxᵢ."}, {"id": "t1-030", "topic": "t1", "q": "Что понимают под «тактом» функционирования полносвязной сети?", "a": ["Прохождение сигнала через один слой", "Одну полную эпоху обучения", "Один обучающий образец выборки", "Полный проход по всей выборке"], "correct": 0, "explanation": "Такт — прохождение сигнала через один слой. Полносвязную сеть, работающую k тактов, можно представить как k-слойную сеть с одинаковыми слоями."}, {"id": "t1-031", "topic": "t1", "q": "В чём роль стандартных функций φ в теореме Колмогорова–Арнольда?", "a": ["Они универсальны и не зависят от f", "Они меняются для каждой функции f", "Они всегда строго линейны", "Они задают число слоёв сети"], "correct": 0, "explanation": "Внутренние функции φ стандартны — одни и те же для любой f; от конкретной функции зависят лишь внешние функции h."}, {"id": "t1-032", "topic": "t1", "q": "Какое представление функции двух переменных даёт теорема Колмогорова?", "a": ["f(x,y)=Σ hq[φq(x)+ψq(y)], q=1..5", "f(x,y)=x·y (произведение)", "f(x,y)=max(x,y) (максимум)", "f(x,y)=sin(x+y) (синус суммы)"], "correct": 0, "explanation": "Для двух переменных: f(x,y)=Σ_{q=1}^{5} hq[φq(x)+ψq(y)] — сумма из пяти слагаемых, что соответствует конечному числу нейронов скрытого слоя."}, {"id": "t1-033", "topic": "t1", "q": "Чем равномерная норма функции отличается от среднеквадратичной?", "a": ["Равномерная — максимум модуля отклонения", "Они всегда совпадают по значению", "Равномерная учитывает только знак", "Среднеквадратичная точна в каждой точке"], "correct": 0, "explanation": "Равномерная (чебышёвская) норма — максимум модуля, гарантирует близость в каждой точке; при среднеквадратичной близость лишь в среднем, а локально отклонение может быть большим."}, {"id": "t1-034", "topic": "t1", "q": "Какое множество является примером ограниченного, но НЕ замкнутого?", "a": ["Открытый интервал (a, b)", "Замкнутый отрезок [a, b]", "Множество натуральных чисел", "Вся числовая прямая R"], "correct": 0, "explanation": "Интервал (a,b) ограничен, но не содержит предельных точек a и b, поэтому не замкнут; отрезок [a,b] и ограничен, и замкнут."}, {"id": "t1-035", "topic": "t1", "q": "Как в доказательстве (теорема Стоуна) реализуется замкнутость класса функций ИНС относительно умножения?", "a": ["Через квадраты: F₁F₂=½((F₁+F₂)²−F₁²−F₂²)", "Простым перемножением весов сети", "Добавлением выходного слоя softmax", "Заменой умножения на сложение"], "correct": 0, "explanation": "Произведение выражают через квадраты сумм и разностей; квадраты реализуются сетью с квадратичной активацией, поэтому класс замкнут относительно умножения."}, {"id": "t1-036", "topic": "t1", "q": "Как в формальной модели задаётся однонейронная «единичная» нейросеть (для условия наличия единицы)?", "a": ["Единичный вес, нулевое смещение, тождественная f", "Нулевые веса и выход через softmax", "Случайные веса без всякого смещения", "Два слоя по сто нейронов в каждом"], "correct": 0, "explanation": "Нейросеть с единичным весом, нулевым смещением и тождественной активацией реализует тождественную (единичную) функцию — выполняется условие наличия единицы в алгебре."}, {"id": "t1-037", "topic": "t1", "q": "Сигнал j-го нейрона слоя n в слоистой сети вычисляется как:", "a": ["Sⱼ=Σ wᵢⱼ·yᵢ, затем yⱼ=f(Sⱼ)", "Sⱼ = максимум входов слоя", "Sⱼ = произведение всех входов", "Sⱼ = softmax входных сигналов"], "correct": 0, "explanation": "Сумматор j-го нейрона n-го слоя складывает взвешенные выходы предыдущего слоя: Sⱼ=Σ wᵢⱼyᵢ, после чего применяется активация yⱼ=f(Sⱼ)."}, {"id": "t1-038", "topic": "t1", "q": "Что обозначает y⁰ⱼ (выход нулевого «слоя») в формализме слоистой сети?", "a": ["Входные сигналы xⱼ для первого слоя", "Выходные значения последнего слоя", "Векторы смещений всех нейронов", "Ошибку обучения на образце"], "correct": 0, "explanation": "Нулевой слой — это вход: y⁰ⱼ = xⱼ. Выходами сети являются значения последнего N-го слоя y^N."}, {"id": "t1-039", "topic": "t1", "q": "Что означает «гетерогенная» (неоднородная) нейронная сеть?", "a": ["Активация зависит от параметров нейрона", "Все нейроны имеют одинаковую активацию", "В сети полностью отсутствуют слои", "Сеть состоит только из сумматоров"], "correct": 0, "explanation": "В гетерогенной сети активационная функция зависит от дополнительных параметров, различных у разных нейронов (в отличие от однородной)."}, {"id": "t2-001", "topic": "t2", "q": "К какому классу алгоритмов относится алгоритм обратного распространения ошибки?", "a": ["Стохастический градиентный спуск", "Методы динамического программирования", "Генетические алгоритмы оптимизации", "Метод ветвей и границ (отсечения)"], "correct": 0, "explanation": "Backprop относится к классу алгоритмов стохастического градиента и применяется для слоистых ИНС."}, {"id": "t2-002", "topic": "t2", "q": "В каком направлении распространяется ошибка при обучении слоистой сети методом backprop?", "a": ["От выходного слоя N к первому", "От первого слоя к последнему", "Только внутри текущего слоя", "В случайном порядке по слоям"], "correct": 0, "explanation": "Значения ошибки g рассчитываются начиная с n=N (выходной слой) и далее до 1 — ошибка распространяется в обратном направлении."}, {"id": "t2-003", "topic": "t2", "q": "С каким значением весов рекомендуется инициализировать сеть в начале алгоритма backprop (из методички)?", "a": ["Случайными числами из [−1, 1]", "Нулевыми значениями весов", "Единичными значениями весов", "Значениями, равными номеру слоя"], "correct": 0, "explanation": "Шаг 1 алгоритма: задать веса случайным образом в диапазоне [-1, 1]."}, {"id": "t2-004", "topic": "t2", "q": "Какое математическое правило лежит в основе вывода формул обратного распространения?", "a": ["Цепное правило сложной функции", "Правило Лопиталя для раскрытия пределов", "Теорема Безу о многочленах", "Правило Крамера для систем"], "correct": 0, "explanation": "Backprop выводится из цепного правила (дифференцирование сложной функции): ошибка передаётся по слоям через производные."}, {"id": "t2-005", "topic": "t2", "q": "Почему обучающие образцы предъявляются сети в случайном порядке?", "a": ["Чтобы сеть не «забывала» часть выборки", "Чтобы ускорить вычисление производных", "Чтобы сократить число слоёв сети", "Чтобы убрать активационные функции"], "correct": 0, "explanation": "Случайный порядок предъявления гарантирует, что сеть не настроится только на образцы определённого вида, «забыв» остальные."}, {"id": "t2-006", "topic": "t2", "q": "Для выходного слоя (n=N) ошибка g в формуле backprop зависит, в частности, от:", "a": ["От производной y(1−y) и разности (d−y)", "Только от номера обрабатываемого слоя", "Только от входных сигналов сети", "От количества пройденных эпох"], "correct": 0, "explanation": "Для логистической активации на выходном слое: g = y(1−y)(d−y), где d — требуемый, y — фактический выход."}, {"id": "t2-007", "topic": "t2", "q": "Как ошибка скрытого слоя (n<N) выражается через следующий слой?", "a": ["Взвешенная сумма ошибок слоя (n+1)", "Через максимум ошибок прошлого слоя", "Независимо от остальных слоёв", "Через сумму входных сигналов"], "correct": 0, "explanation": "Для n<N: gⱼ = yⱼ(1−yⱼ)·Σ gᵢ^{n+1}·wⱼᵢ^{n+1} — ошибка собирается с последующего слоя и умножается на производную активации."}, {"id": "t2-008", "topic": "t2", "q": "Как корректируются веса на каждом шаге алгоритма обратного распространения?", "a": ["Δw ∝ скорость × ошибка × вход", "Веса заменяются средними входов", "Веса обнуляются после образца", "Веса увеличиваются на константу"], "correct": 0, "explanation": "Поправка: wᵢⱼ ← wᵢⱼ + λ·gⱼ·yᵢ, то есть пропорционально скорости обучения λ, ошибке gⱼ и выходу предыдущего слоя yᵢ."}, {"id": "t2-009", "topic": "t2", "q": "Какова производная логистической (сигмоидной) функции, удобно выражаемая через саму функцию?", "a": ["f'(s) = f(s)·(1 − f(s))", "f'(s) = 1 − f(s)·f(s)", "f'(s) = f(s)", "f'(s) = 1/f(s)"], "correct": 0, "explanation": "Для сигмоиды f' = f·(1−f). Именно это свойство (производная через значение функции) удобно для backprop."}, {"id": "t2-010", "topic": "t2", "q": "Чему равна производная гиперболического тангенса tanh, используемая в backprop?", "a": ["1 − tanh²(s)", "tanh(s)·(1 − tanh(s))", "tanh(s)", "1/(1 + tanh(s))"], "correct": 0, "explanation": "Производная tanh: (tanh)' = 1 − tanh². Это используется при обратном распространении в РНС с tanh."}, {"id": "t2-011", "topic": "t2", "q": "При критерии в виде кросс-энтропии и softmax на выходе произведение l'·f'_y для верного класса (p=1) принимает вид:", "a": ["y_k − 1", "y_k", "1 − y_k²", "0"], "correct": 0, "explanation": "Для softmax+кросс-энтропия: для верного класса (p_k=1) производная по аргументу равна y_k − 1, для остальных — y_k. Это сильно упрощает backprop."}, {"id": "t2-012", "topic": "t2", "q": "Какая комбинация (критерий + активация выхода) даёт особенно простое выражение для производной?", "a": ["Кросс-энтропия + softmax", "MSE + линейная активация", "MAE + ReLU", "Hinge-потеря + сигмоида"], "correct": 0, "explanation": "Связка softmax + кросс-энтропия даёт простую производную (y_k − 1 или y_k), что упрощает обратное распространение в задачах классификации."}, {"id": "t2-013", "topic": "t2", "q": "Что из перечисленного относится к «возможным трудностям» backprop (тема 2 структуры лекций)?", "a": ["Затухание/взрыв градиентов, минимумы", "Невозможность задать веса сети", "Отсутствие любых активационных функций", "Необходимость решать СЛАУ точно"], "correct": 0, "explanation": "Среди трудностей backprop — проблемы затухающих/взрывающихся градиентов, локальные минимумы и плато, чувствительность к инициализации."}, {"id": "t2-014", "topic": "t2", "q": "Что вычисляется на шаге прямого прохода перед обратным распространением?", "a": ["Выходы всех нейронов по слоям", "Только градиенты весов сети", "Только потери без выходов сети", "Случайная перестановка весов"], "correct": 0, "explanation": "Сначала на вход подаётся образец и рассчитываются выходы нейронов от 1-го слоя до последнего; затем по ним выполняется обратный проход."}, {"id": "t2-015", "topic": "t2", "q": "Когда обучение в простейшем алгоритме backprop считается завершённым?", "a": ["Когда ошибка перестаёт быть значимой", "Когда все веса станут равны единице", "Ровно после первого образца", "Когда число слоёв достигнет N"], "correct": 0, "explanation": "Сеть периодически тестируют; если ошибка существенна — продолжают (go to start), иначе обучение завершают."}, {"id": "t2-016", "topic": "t2", "q": "Производная активационной функции в backprop вычисляется «через значения самой функции». Зачем это нужно?", "a": ["Эти значения уже есть с прямого прохода", "Чтобы вовсе не использовать веса сети", "Чтобы увеличить число параметров", "Это якобы гарантирует глобальный минимум"], "correct": 0, "explanation": "Если производная выражается через f (как у сигмоиды f(1−f)), её не нужно считать заново — экономятся вычисления, ведь f уже получено на прямом проходе."}, {"id": "t2-017", "topic": "t2", "q": "Чем отличается «пакетное» (batch) обновление весов от стохастического (по одному образцу)?", "a": ["Градиент усредняется по пакету", "Пакетное не использует производные", "Стохастическое меняет все слои разом", "Между ними нет никаких различий"], "correct": 0, "explanation": "При пакетном обучении градиент усредняется по группе образцов (батчу), что снижает дисперсию шага; при чистом SGD — по одному образцу."}, {"id": "t2-018", "topic": "t2", "q": "Что обозначает символ λ в формуле коррекции весов backprop?", "a": ["Скорость обучения (learning rate)", "Спектральную норму весовой матрицы", "Число слоёв в нейросети", "Коэффициент L2-регуляризации"], "correct": 0, "explanation": "λ — скорость обучения (шаг), задающая величину поправки веса в направлении антиградиента."}, {"id": "t2-019", "topic": "t2", "q": "Почему backprop эффективнее наивного вычисления градиента по каждому весу отдельно?", "a": ["Переиспользует промежуточные производные", "Не требует прямого прохода вовсе", "Не использует цепное правило", "Находит точное решение без производных"], "correct": 0, "explanation": "Backprop вычисляет градиенты за один обратный проход, переиспользуя промежуточные величины (ошибки слоёв), вместо независимого пересчёта для каждого веса."}, {"id": "t2-020", "topic": "t2", "q": "Требуемые значения выходов d_j в алгоритме backprop — это:", "a": ["Целевые выходы из обучающей выборки", "Случайно сгенерированные числа", "Выходы с предыдущей эпохи обучения", "Усреднённые веса последнего слоя"], "correct": 0, "explanation": "d_j — требуемые (эталонные) значения выходов для k-го образца; разность (d−y) формирует ошибку выходного слоя."}, {"id": "t2-021", "topic": "t2", "q": "Что обычно называют одной эпохой обучения?", "a": ["Полный проход по всей выборке", "Обработку одного обучающего образца", "Один слой нейросети", "Однократное обновление веса"], "correct": 0, "explanation": "Эпоха — это один полный проход алгоритма по всем обучающим примерам (как правило, в случайном порядке)."}, {"id": "t2-022", "topic": "t2", "q": "К чему приводит слишком большая скорость обучения λ?", "a": ["Расходимость или колебания у минимума", "Гарантированную сходимость к минимуму", "Полное отсутствие изменений весов", "Удаление скрытых слоёв сети"], "correct": 0, "explanation": "При слишком большом шаге обновления «перепрыгивают» минимум, вызывая колебания или расходимость; слишком малый шаг — очень медленное обучение."}, {"id": "t2-023", "topic": "t2", "q": "Почему сигмоидная активация способствует затуханию градиента в глубоких сетях?", "a": ["Её производная мала (≤ 0.25)", "Её производная всегда больше 1", "У сигмоиды нет производной", "Она не нужна в скрытых слоях"], "correct": 0, "explanation": "Максимум производной сигмоиды — 0.25; при перемножении таких множителей по многим слоям градиент экспоненциально затухает (vanishing gradient)."}, {"id": "t2-024", "topic": "t2", "q": "Почему нельзя инициализировать все веса сети одинаковыми (например, нулями)?", "a": ["Нейроны останутся симметричными", "Сеть станет обучаться слишком быстро", "Градиент станет бесконечным", "Это запрещает цепное правило"], "correct": 0, "explanation": "При одинаковых весах все нейроны слоя получают идентичные градиенты и обновления — симметрия не разрывается, и они остаются дубликатами. Поэтому веса инициализируют случайно."}, {"id": "t2-025", "topic": "t2", "q": "В каком направлении делается шаг по весам при градиентном спуске?", "a": ["В направлении антиградиента потерь", "В направлении градиента (рост)", "Перпендикулярно градиенту потерь", "В полностью случайном направлении"], "correct": 0, "explanation": "Минимизация требует движения против градиента: w ← w − λ·∂L/∂w, то есть в сторону наискорейшего убывания потерь."}, {"id": "t2-026", "topic": "t2", "q": "Каков порядок вычислений в одном цикле backprop?", "a": ["Прямой проход → обратный → коррекция", "Сначала коррекция, потом прямой проход", "Только обратный проход без прямого", "Случайный порядок обработки слоёв"], "correct": 0, "explanation": "Сначала прямой проход вычисляет выходы всех слоёв, затем обратный проход распространяет ошибку и считает градиенты, после чего веса корректируются."}, {"id": "t2-027", "topic": "t2", "q": "Что выражает величина gⱼⁿ («дельта») в алгоритме обратного распространения?", "a": ["Чувствительность потерь к сумматору", "Текущее значение синаптического веса", "Выход активационной функции", "Скорость обучения сети"], "correct": 0, "explanation": "g (дельта) — это градиент потерь по выходу сумматора нейрона; через него по цепному правилу выражаются градиенты по всем весам, входящим в нейрон."}, {"id": "t2-028", "topic": "t2", "q": "Почему backprop особенно чувствителен к выбору начальных весов?", "a": ["Влияет на затухание/взрыв сигналов", "Начальные веса не влияют на итог", "Веса всегда сходятся к одному", "Инициализация задаёт число классов"], "correct": 0, "explanation": "Масштаб начальных весов определяет масштаб активаций и градиентов; плохой выбор приводит к затуханию/взрыву и попаданию в неудачные локальные минимумы или плато."}, {"id": "t2-029", "topic": "t2", "q": "Что такое локальный минимум применительно к обучению сети?", "a": ["Минимум локально, но не глобально", "Точка глобального максимума потерь", "Набор весов, равных нулю", "Минимальное число слоёв сети"], "correct": 0, "explanation": "Поверхность потерь невыпукла; градиентный спуск может остановиться в локальном минимуме (или на плато), где потери не наименьшие во всём пространстве."}, {"id": "t2-030", "topic": "t2", "q": "Какова вычислительная сложность одного прохода backprop относительно числа слоёв/связей?", "a": ["Линейная по числу связей", "Экспоненциальная по числу слоёв", "Кубическая по числу нейронов", "Не зависит от размера сети"], "correct": 0, "explanation": "За счёт переиспользования промежуточных величин обратный проход стоит примерно столько же, сколько прямой — линейно по числу связей."}, {"id": "t2-031", "topic": "t2", "q": "Градиент квадратичной функции потерь L=½(d−y)² по выходу y равен:", "a": ["−(d − y)", "(d − y)²", "2(d + y)", "1/(d − y)"], "correct": 0, "explanation": "∂L/∂y = −(d−y) = (y−d). Это формирует ошибку выходного слоя, далее умножаемую на производную активации."}, {"id": "t3-001", "topic": "t3", "q": "В чём ключевое отличие задачи машинного обучения от задачи чистой оптимизации?", "a": ["Малая train-ошибка — лишь средство обобщения", "В МО полностью отсутствует функция потерь", "Оптимизация не использует градиенты", "В МО всегда достигается глобальный минимум"], "correct": 0, "explanation": "В оптимизации цель — минимум функции; в МО минимизация эмпирического риска на обучении лишь средство для хорошего обобщения на новых (тестовых) данных."}, {"id": "t3-002", "topic": "t3", "q": "Какую функцию потерь типично используют для задач регрессии (вещественный выход)?", "a": ["Среднеквадратичную ошибку (MSE)", "Бинарную кросс-энтропию (BCE)", "Категориальную кросс-энтропию", "Hinge-потерю для классификатора"], "correct": 0, "explanation": "Для регрессии с произвольными вещественными выходами применяют MSE (квадратичную ошибку); кросс-энтропия предназначена для вероятностных/классификационных задач."}, {"id": "t3-003", "topic": "t3", "q": "Какую функцию потерь используют, когда выход — вероятности отнесения к классу?", "a": ["Кросс-энтропию (Cross Entropy)", "Среднеквадратичную ошибку MSE", "Среднюю абсолютную ошибку MAE", "Косинусное расстояние векторов"], "correct": 0, "explanation": "Для классификации (включая предсказание токенов/слов) используют кросс-энтропию, в т.ч. Binary Cross Entropy Loss для бинарного случая."}, {"id": "t3-004", "topic": "t3", "q": "Что является основной целью процесса обучения глубокой нейронной сети?", "a": ["Точечные оценки весов сети", "Интервальные оценки каждого веса", "Минимизацию числа слоёв", "Запоминание всей выборки"], "correct": 0, "explanation": "Цель обучения ГНС — получить точечные (не интервальные) оценки параметров сети, то есть значения синаптических весов."}, {"id": "t3-005", "topic": "t3", "q": "Какие три свойства, по статистике, делают точечную оценку параметров «хорошей»?", "a": ["Состоятельность, несмещённость, эффективность", "Линейность, выпуклость, дифференцируемость", "Монотонность, ограниченность, периодичность", "Полнота, ортогональность, нормированность"], "correct": 0, "explanation": "Хорошая точечная оценка обладает состоятельностью (сходимость по вероятности), несмещённостью и эффективностью (минимальная дисперсия)."}, {"id": "t3-006", "topic": "t3", "q": "Что означает состоятельность оценки параметра?", "a": ["Сходимость к истинному значению", "Равенство оценки нулю", "Полная независимость оценки от данных", "Постоянство дисперсии оценки"], "correct": 0, "explanation": "Состоятельность — сходимость оценки по вероятности к истинному значению параметра при увеличении объёма выборки N."}, {"id": "t3-007", "topic": "t3", "q": "Какой алгоритм оптимизации является базовым для обучения ГНС?", "a": ["Стохастический градиентный спуск", "Симплекс-метод линейного программирования", "Метод исключения Гаусса", "Метод золотого сечения"], "correct": 0, "explanation": "Базовый метод — стохастический градиентный спуск (SGD); его расширения (момент, Adam и др.) улучшают сходимость."}, {"id": "t3-008", "topic": "t3", "q": "Идея импульсного (моментного) метода оптимизации заключается в том, что:", "a": ["Накопление прошлых градиентов (инерция)", "Шаг полностью обнуляется каждую итерацию", "Используется только второй градиент", "Скорость обучения растёт линейно"], "correct": 0, "explanation": "Моментный метод добавляет «инерцию»: обновление учитывает накопленные прошлые градиенты, что сглаживает траекторию и ускоряет сходимость в оврагах."}, {"id": "t3-009", "topic": "t3", "q": "Чем метод Нестерова отличается от классического момента?", "a": ["Градиент берётся с «заглядыванием вперёд»", "Он вообще не использует градиент", "Работает исключительно для линейных моделей", "Он удаляет смещения из сети"], "correct": 0, "explanation": "Метод Нестерова (NAG) вычисляет градиент в «упреждённой» точке (после применения момента), что даёт более точную коррекцию."}, {"id": "t3-010", "topic": "t3", "q": "Ключевая особенность AdaGrad состоит в том, что он:", "a": ["Свой шаг на параметр по сумме квадратов", "Одинаковый шаг для всех параметров", "Совсем не хранит историю градиентов", "Применим лишь к свёрточным слоям сети"], "correct": 0, "explanation": "AdaGrad масштабирует шаг индивидуально для каждого параметра, деля на корень из накопленной суммы квадратов его градиентов; редкие признаки получают больший шаг."}, {"id": "t3-011", "topic": "t3", "q": "Какую проблему AdaGrad решает RMSProp?", "a": ["Затухание шага — берёт скользящее среднее", "Отсутствие смещений в сети", "Слишком большое число слоёв", "Невозможность вообще вычислить градиент"], "correct": 0, "explanation": "В AdaGrad сумма квадратов растёт неограниченно и шаг затухает к нулю. RMSProp использует экспоненциальное скользящее среднее, не давая шагу затухнуть."}, {"id": "t3-012", "topic": "t3", "q": "Что объединяет в себе оптимизатор Adam?", "a": ["Момент и RMSProp (1-й и 2-й моменты)", "Только метод Ньютона второго порядка", "Только идею AdaGrad", "Случайный поиск без градиентов"], "correct": 0, "explanation": "Adam (Adaptive Moment Estimation) сочетает идею момента (1-й момент градиента) и RMSProp (2-й момент), с коррекцией смещения оценок."}, {"id": "t3-013", "topic": "t3", "q": "Чем AdamW отличается от обычного Adam?", "a": ["Weight decay отделён от градиента", "AdamW не использует момент вовсе", "AdamW работает без скорости обучения", "AdamW предназначен только для RNN"], "correct": 0, "explanation": "AdamW отделяет регуляризацию весов (decoupled weight decay) от адаптивного шага, что улучшает обобщение по сравнению с добавлением L2 прямо в градиент."}, {"id": "t3-014", "topic": "t3", "q": "К какому классу относится метод Ньютона в оптимизации?", "a": ["К методам второго порядка (Гессе)", "К методам нулевого порядка", "К эволюционным методам оптимизации", "К методам первого порядка"], "correct": 0, "explanation": "Метод Ньютона — метод второго порядка: использует Гессиан (вторые производные). В ГНС применяется редко из-за дороговизны вычисления и хранения Гессе."}, {"id": "t3-015", "topic": "t3", "q": "Что делает регуляризация Тихонова (L2, гребневая регрессия / weight decay)?", "a": ["Штраф ~ сумме квадратов весов", "Удаляет случайные нейроны сети", "Нормирует входные данные сети", "Увеличивает скорость обучения"], "correct": 0, "explanation": "L2-регуляризация (Тихонов / снижение весов) добавляет штраф ~Σwᵢ², «прижимая» веса к нулю и уменьшая переобучение."}, {"id": "t3-016", "topic": "t3", "q": "Чем характерна L1-регуляризация по сравнению с L2?", "a": ["Даёт разрежённость (зануляет веса)", "Всегда увеличивает все веса", "Полностью эквивалентна методу dropout", "Никак не влияет на веса"], "correct": 0, "explanation": "L1-штраф (Σ|wᵢ|) стимулирует разрежённость решения — многие веса становятся точно нулевыми, отбирая признаки."}, {"id": "t3-017", "topic": "t3", "q": "В чём суть метода Dropout (прореживание)?", "a": ["Случайно отключает часть нейронов", "Безвозвратно удаляет слои из сети", "Нормирует значения градиентов", "Увеличивает размер батча вдвое"], "correct": 0, "explanation": "Dropout на каждом шаге обучения случайно «выключает» часть нейронов, заставляя сеть не полагаться на отдельные нейроны и улучшая обобщение."}, {"id": "t3-018", "topic": "t3", "q": "Что делает пакетная нормализация (Batch Normalization)?", "a": ["Нормирует активации по мини-батчу", "Удаляет батчи из обучения совсем", "Заменяет функцию потерь сети", "Полностью отключает градиенты"], "correct": 0, "explanation": "BatchNorm нормирует выходы слоя по среднему и дисперсии мини-батча (с обучаемыми γ, β), что ускоряет и стабилизирует обучение."}, {"id": "t3-019", "topic": "t3", "q": "Что такое аугментация данных?", "a": ["Расширение выборки преобразованиями", "Удаление части обучающих данных", "Уменьшение числа классов задачи", "Замена данных случайными числами"], "correct": 0, "explanation": "Аугментация увеличивает обучающую выборку за счёт допустимых преобразований исходных данных, повышая устойчивость и снижая переобучение."}, {"id": "t3-020", "topic": "t3", "q": "Как шум может использоваться при обучении ГНС?", "a": ["Как аугментация и регуляризация", "Только как помеха, требующая удаления", "Для увеличения числа слоёв", "Для отключения backprop"], "correct": 0, "explanation": "Добавление шума (к входам, весам или меткам) выступает формой аугментации и регуляризации, повышая устойчивость модели."}, {"id": "t3-021", "topic": "t3", "q": "В чём идея ранней остановки (early stopping)?", "a": ["Стоп, когда валидация не улучшается", "Остановка всегда после первой эпохи", "Удаление выходного слоя сети", "Фиксация скорости обучения навсегда"], "correct": 0, "explanation": "Ранняя остановка прекращает обучение при росте/застое валидационной ошибки, предотвращая переобучение."}, {"id": "t3-022", "topic": "t3", "q": "Что делает стратегия Reduce on Plateau (RoP)?", "a": ["Снижает скорость при выходе на плато", "Увеличивает число нейронов на плато", "Полностью останавливает обучение", "Меняет функцию активации сети"], "correct": 0, "explanation": "RoP уменьшает скорость обучения, когда отслеживаемая метрика перестаёт улучшаться (выходит на плато), помогая дообучению."}, {"id": "t3-023", "topic": "t3", "q": "Что такое gradual warmup в расписании скорости обучения?", "a": ["Постепенный рост скорости в начале", "Резкое обнуление скорости в конце", "Удаление разогрева перед инференсом", "Увеличение размера всей сети"], "correct": 0, "explanation": "Warmup — плавное повышение скорости обучения на первых шагах (часто с последующим косинусным снижением), что стабилизирует ранние этапы обучения."}, {"id": "t3-024", "topic": "t3", "q": "Идея Warm Restarts состоит в том, что:", "a": ["Скорость периодически разогревается", "Сеть каждый раз стартует с нуля", "Веса обнуляются на каждом батче", "Используется лишь один цикл обучения"], "correct": 0, "explanation": "Warm Restarts периодически повышают скорость обучения, давая оптимизатору шанс выйти из узких минимумов и исследовать пространство параметров."}, {"id": "t3-025", "topic": "t3", "q": "Зачем нужна правильная инициализация весов ГНС?", "a": ["Избежать затухания/взрыва сигналов", "Чтобы зафиксировать веса навсегда", "Чтобы убрать активационные функции", "Чтобы увеличить число классов"], "correct": 0, "explanation": "Грамотная инициализация (например, Ксавье/Glorot) сохраняет масштаб активаций и градиентов по слоям, предотвращая их затухание или взрыв."}, {"id": "t3-026", "topic": "t3", "q": "Инициализация Ксавье (Glorot) подбирает дисперсию начальных весов исходя из:", "a": ["Числа входов и выходов слоя", "Номера текущей эпохи обучения", "Размера обучающего батча", "Значения функции потерь"], "correct": 0, "explanation": "Инициализация Ксавье масштабирует веса по числу входов и выходов слоя, чтобы дисперсия сигналов оставалась стабильной при прохождении по сети."}, {"id": "t3-027", "topic": "t3", "q": "Что обычно делают со смещениями (bias) при инициализации?", "a": ["Инициализируют нулями", "Большими случайными числами", "Приравнивают к весам слоя", "Не используют их вовсе"], "correct": 0, "explanation": "Смещения обычно инициализируют нулями (иногда малыми константами), так как симметрию уже разрывает случайная инициализация весов."}, {"id": "t3-028", "topic": "t3", "q": "Какая метрика типична для оценки качества задач классификации?", "a": ["Accuracy, precision, recall, F1", "Среднеквадратичную ошибку MSE", "Перплексию языковой модели", "Спектральную норму матрицы"], "correct": 0, "explanation": "Для классификации используют accuracy, точность (precision), полноту (recall), F1 и т.п.; MSE — метрика регрессии."}, {"id": "t3-029", "topic": "t3", "q": "Какой приём помогает бороться с неравновероятностью (несбалансированностью) классов?", "a": ["Взвешивание классов в потере", "Удаление функции активации", "Рост скорости обучения вдвое", "Отключение backprop для классов"], "correct": 0, "explanation": "При дисбалансе классов применяют взвешивание потерь по классам, oversampling редких или undersampling частых классов."}, {"id": "t3-030", "topic": "t3", "q": "Что такое агрегация функций потерь?", "a": ["Составной критерий из нескольких потерь", "Удаление одной из используемых потерь", "Замена функции потерь готовой метрикой", "Нормировка входных данных сети"], "correct": 0, "explanation": "Несколько функций потерь можно агрегировать (например, взвешенной суммой) в один составной критерий оптимизации для многозадачного обучения."}, {"id": "t3-031", "topic": "t3", "q": "Зачем при обучении используют пакеты (батчи) вместо всей выборки сразу?", "a": ["Баланс точности градиента и затрат", "Чтобы полностью исключить градиенты", "Чтобы уменьшить число классов", "Батчи не влияют на обучение"], "correct": 0, "explanation": "Мини-батчи дают достаточно точную оценку градиента при умеренных затратах памяти и времени и добавляют полезный стохастический шум."}, {"id": "t3-032", "topic": "t3", "q": "Что показывает метрика accuracy (точность классификации)?", "a": ["Долю правильно классифицированных", "Среднеквадратичную ошибку модели", "Число параметров модели", "Скорость обучения сети"], "correct": 0, "explanation": "Accuracy — доля верных предсказаний среди всех. При дисбалансе классов она может вводить в заблуждение, поэтому дополняют precision/recall/F1."}, {"id": "t3-033", "topic": "t3", "q": "Что измеряет полнота (recall)?", "a": ["Долю найденных из всех истинных «+»", "Долю верных среди предсказанных «+»", "Среднюю ошибку регрессии", "Число эпох до сходимости"], "correct": 0, "explanation": "Recall = TP/(TP+FN) — какую долю реальных положительных объектов модель обнаружила. Precision = TP/(TP+FP) — какая доля предсказанных положительных верна."}, {"id": "t3-034", "topic": "t3", "q": "Что такое F1-мера?", "a": ["Гармоническое среднее P и R", "Простую сумму precision и recall", "Среднеквадратичную ошибку модели", "Максимум из precision и recall"], "correct": 0, "explanation": "F1 = 2·P·R/(P+R) — гармоническое среднее точности и полноты, балансирующее их; полезно при несбалансированных классах."}, {"id": "t3-035", "topic": "t3", "q": "Почему momentum помогает в «оврагах» (ravines) поверхности потерь?", "a": ["Инерция гасит колебания поперёк оврага", "Он увеличивает шум градиента", "Он полностью обнуляет градиент", "Он уменьшает число параметров"], "correct": 0, "explanation": "В узких «оврагах» обычный SGD колеблется поперёк; момент усредняет градиенты, гасит поперечные колебания и ускоряет продвижение вдоль направления минимума."}, {"id": "t3-036", "topic": "t3", "q": "Зачем в Adam применяется коррекция смещения (bias correction) оценок моментов?", "a": ["Компенсирует смещение к нулю в начале", "Чтобы увеличить скорость обучения сети", "Чтобы убрать второй момент", "Чтобы заменить softmax"], "correct": 0, "explanation": "Экспоненциальные средние моментов инициализируются нулями и на старте смещены к нулю; коррекция (деление на 1−β^t) устраняет это смещение."}, {"id": "t3-037", "topic": "t3", "q": "Почему методы второго порядка (Ньютона) редко применяют напрямую в больших ГНС?", "a": ["Матрица Гессе слишком дорогая", "Они не используют градиент вовсе", "Они всегда расходятся", "Работают лишь для линейных задач"], "correct": 0, "explanation": "Гессиан имеет размер (число параметров)², его вычисление/обращение неподъёмно для миллионов параметров; поэтому используют методы первого порядка или приближения."}, {"id": "t3-038", "topic": "t3", "q": "Как L2-регуляризация (weight decay) влияет на веса при обновлении?", "a": ["Стягивает веса к нулю каждый шаг", "Увеличивает все веса ровно вдвое", "Зануляет случайно выбранные веса", "Не меняет шаг обновления"], "correct": 0, "explanation": "Штраф ½α·Σw² даёт в градиенте слагаемое αw, из-за чего каждый шаг немного уменьшает веса (decay), ограничивая их рост и переобучение."}, {"id": "t3-039", "topic": "t3", "q": "Что характерно для переобучения (overfitting)?", "a": ["Мала train-ошибка, велика test", "Велика ошибка и на train, и на test", "Одинаково малая ошибка везде", "Полное отсутствие функции потерь"], "correct": 0, "explanation": "Переобучение — модель «запомнила» обучающую выборку (малая train-ошибка), но плохо обобщает (большая test-ошибка). С ним борются регуляризацией, dropout, ранней остановкой."}, {"id": "t3-040", "topic": "t3", "q": "Что такое недообучение (underfitting)?", "a": ["Модель проста, велика train-ошибка", "Идеальная подгонка под шум обучения", "Только проблема тестовой выборки", "Слишком быстрая сходимость к нулю"], "correct": 0, "explanation": "При недообучении модель недостаточно выразительна/недоучена: высокая ошибка уже на обучающей выборке. Лечится усложнением модели или более долгим обучением."}, {"id": "t3-041", "topic": "t3", "q": "Как при инференсе обычно компенсируют отключение нейронов, применявшееся в Dropout при обучении?", "a": ["Масштабируют активации на p", "Полностью отключают все нейроны сети", "Удваивают число слоёв сети", "Меняют функцию потерь"], "correct": 0, "explanation": "На инференсе dropout не применяют, а выходы масштабируют (или используют inverted dropout при обучении), чтобы ожидаемая величина активаций соответствовала обучению."}, {"id": "t3-042", "topic": "t3", "q": "Какие обучаемые параметры есть у слоя пакетной нормализации (BatchNorm)?", "a": ["Масштаб γ и сдвиг β", "Только веса свёртки", "Нет обучаемых параметров", "Скорость обучения и момент"], "correct": 0, "explanation": "После нормировки по статистикам батча BatchNorm применяет обучаемые γ (масштаб) и β (сдвиг), позволяя сети при необходимости восстановить исходное распределение."}, {"id": "t3-043", "topic": "t3", "q": "В чём преимущество косинусного снижения скорости обучения (cosine decay)?", "a": ["Плавное снижение шага к концу", "Резкое обнуление шага в начале", "Постоянная скорость всё обучение", "Рост скорости обучения к концу"], "correct": 0, "explanation": "Косинусное расписание плавно снижает скорость по косинусоиде, давая крупные шаги в начале и аккуратное «дошлифовывание» в конце обучения."}, {"id": "t3-044", "topic": "t3", "q": "Чем отличается стохастический градиентный спуск от пакетного (full-batch) градиентного спуска?", "a": ["SGD — по части данных (с шумом)", "SGD не использует градиент вовсе", "Full-batch быстрее на каждом шаге", "Они полностью идентичны"], "correct": 0, "explanation": "SGD считает градиент по одному образцу/мини-батчу — дешевле и с полезным шумом (помогает выходить из плохих минимумов); full-batch точнее, но дороже и медленнее."}, {"id": "t3-045", "topic": "t3", "q": "Зачем нормируют (стандартизуют) входные признаки перед обучением?", "a": ["Привести признаки к общему масштабу", "Чтобы увеличить число классов", "Чтобы убрать активационные функции", "Это нужно только для RNN-сетей"], "correct": 0, "explanation": "Признаки разного масштаба деформируют поверхность потерь и замедляют градиентный спуск; нормировка (например, к нулевому среднему и единичной дисперсии) выравнивает масштабы."}, {"id": "t4-001", "topic": "t4", "q": "Какую операцию в СНС называют «свёрткой», хотя формально это:", "a": ["Перекрёстная корреляция (без обращения)", "Классическая свёртка с обращением ядра", "Дискретное преобразование Фурье", "Операция пространственного пулинга"], "correct": 0, "explanation": "В СНС «свёрткой» называют перекрёстную корреляцию: s(n)=Σ w(m)x(n+m) — ядро не «переворачивается», как в классической свёртке."}, {"id": "t4-002", "topic": "t4", "q": "С тензорами какого ранга преимущественно работают в СНС?", "a": ["Ранга 3 (3D-массив N₁×N₂×K)", "Ранга 0 (только скаляры)", "Ранга 1 (только векторы)", "Ранга 5 и выше (4D+)"], "correct": 0, "explanation": "В СНС в основном используют 3D-тензоры (ранга 3): высота × ширина × число каналов (карт признаков)."}, {"id": "t4-003", "topic": "t4", "q": "Что называют картой признаков (feature map) в СНС?", "a": ["Результат свёртки с одним ядром", "Вектор весов одного нейрона", "Скаляр значения функции потерь", "Список меток классов выхода"], "correct": 0, "explanation": "Результат свёртки с одним ядром — пространственно двумерный тензор, интерпретируемый как карта (поле) признака."}, {"id": "t4-004", "topic": "t4", "q": "Какой пространственный размер выхода даёт «корректная» (valid) свёртка ядром M₁×M₂ для входа N₁×N₂?", "a": ["(N₁−M₁+1) × (N₂−M₂+1)", "N₁ × N₂ (без изменений)", "(N₁+M₁) × (N₂+M₂)", "M₁ × M₂ (размер ядра)"], "correct": 0, "explanation": "При valid-свёртке (ядро целиком помещается во входе) выходной размер равен (N₁−M₁+1)×(N₂−M₂+1) — он уменьшается с ростом ядра."}, {"id": "t4-005", "topic": "t4", "q": "Что такое padding (дополнение) и зачем он нужен?", "a": ["Дополнение краёв (нулями) тензора", "Удаление крайних строк входного тензора", "Замена ядра на единичное", "Прореживание карт признаков"], "correct": 0, "explanation": "Padding добавляет значения (чаще нули) по границам входа; при сохранении размеров входа и выхода свёртку называют конгруэнтной (флаг 'same')."}, {"id": "t4-006", "topic": "t4", "q": "Какую свёртку называют конгруэнтной (флаг 'same' в пакетах)?", "a": ["Когда размеры входа и выхода равны", "Когда ядро имеет размер 1×1", "Когда шаг равен размеру ядра", "Когда нет активационной функции"], "correct": 0, "explanation": "Конгруэнтная свёртка сохраняет пространственный размер: достигается дополнением (padding), флаг 'same'."}, {"id": "t4-007", "topic": "t4", "q": "Сколько обучаемых параметров у одного свёрточного фильтра размера M₁×M₂ при K каналах входа?", "a": ["M₁·M₂·K + 1 (со смещением)", "M₁ + M₂ + K (сумма)", "M₁·M₂ без учёта каналов", "N₁·N₂·K по входу"], "correct": 0, "explanation": "Фильтр свёртки имеет M₁·M₂·K весов плюс одно смещение (bias), итого M₁·M₂·K+1 параметров на фильтр."}, {"id": "t4-008", "topic": "t4", "q": "Что вычисляет поточечная свёртка 1×1 (ядро 1×1×K)?", "a": ["Скалярное произведение по каналам в точке", "Максимум по окну 1×1", "Среднее по всем каналам и пространству", "Поворот входного изображения"], "correct": 0, "explanation": "Свёртка 1×1 в каждой точке (n₁,n₂) считает скалярное произведение по каналам — это проекция вектора-признака в новое пространство (аналог однослойного перцептрона)."}, {"id": "t4-009", "topic": "t4", "q": "Главное преимущество свёрточных слоёв перед полносвязными в обработке изображений:", "a": ["Резко меньше параметров при тех же связях", "Полное отсутствие параметров", "Принципиальная невозможность переобучения", "Полный отказ от активационных функций"], "correct": 0, "explanation": "Благодаря разделению весов (один фильтр на всё поле) свёртки на порядки снижают число параметров при сохранении числа нейронных связей."}, {"id": "t4-010", "topic": "t4", "q": "Что такое поле восприятия (receptive field) фильтра СНС?", "a": ["Область входа, влияющая на выход", "Число классов на выходном слое", "Размер всей обучающей выборки", "Скорость обучения слоя"], "correct": 0, "explanation": "Receptive field — участок входа, на который «смотрит» нейрон. С глубиной накопленное поле восприятия растёт, позволяя улавливать всё более крупные структуры."}, {"id": "t4-011", "topic": "t4", "q": "Почему часто выгоднее два последовательных ядра 3×3, чем одно 5×5?", "a": ["То же поле 5×5, но меньше параметров", "Ядро 5×5 нельзя реализовать программно", "Ядра 3×3 не требуют обучения", "Два 3×3 дают поле больше 5×5"], "correct": 0, "explanation": "Каскад из двух 3×3 даёт эффективное поле 5×5, но требует 2·(3·3·K+1)=18K+2 параметров против 25K+1 у 5×5, плюс добавляет нелинейность."}, {"id": "t4-012", "topic": "t4", "q": "Что делает слой max-пулинга?", "a": ["Берёт максимум в локальном окне", "Усредняет все каналы карты в один", "Применяет softmax к окну", "Добавляет нули по краям"], "correct": 0, "explanation": "Max-пулинг берёт локальный максимум в окне (независимо по каждой карте признаков), обеспечивая инвариантность к малым сдвигам."}, {"id": "t4-013", "topic": "t4", "q": "Сколько обучаемых параметров у слоя пулинга?", "a": ["Обучаемых параметров нет", "Столько же, сколько у свёртки", "По одному на карту признаков", "Зависит от числа классов"], "correct": 0, "explanation": "Пулинг не имеет обучаемых параметров; задаются лишь метапараметры — размер окна, шаги (stride) и тип (max/average)."}, {"id": "t4-014", "topic": "t4", "q": "Что делает функция Flatten в типовой СНС?", "a": ["Разворачивает 3D-тензор в вектор", "Уменьшает число каналов до одного", "Применяет свёртку 1×1", "Нормирует значения тензора"], "correct": 0, "explanation": "Flatten («разглаживание») преобразует трёхмерный тензор в одномерный вектор длины N₁·N₂·K для подачи в полносвязные слои."}, {"id": "t4-015", "topic": "t4", "q": "Как выглядит типовая архитектура СНС в обобщённой записи?", "a": ["INPUT→[CONV→RELU→POOL]*M→FC→SOFTMAX", "INPUT→[POOL→CONV]*M→RELU→FC→SOFTMAX", "INPUT→FC→CONV→POOL→SOFTMAX", "POOL→INPUT→RELU→CONV→FC"], "correct": 0, "explanation": "Типовая СНС: чередование свёрток с ReLU и пулингов, затем разворот и полносвязные слои, завершаясь softmax для классификации."}, {"id": "t4-016", "topic": "t4", "q": "В чём суть приёма «бутылочное горлышко» (bottleneck)?", "a": ["Сжать тензор и вернуть размер", "Удалить все скрытые слои", "Добавить шум к входу сети", "Заменить свёртку пулингом"], "correct": 0, "explanation": "Bottleneck сжимает представление (часто свёрткой 1×1) до меньшего размера, снижая число параметров/вычислений, а затем при необходимости расширяет обратно."}, {"id": "t4-017", "topic": "t4", "q": "Какой приём передачи информации (y = F(x) + x) и в какой архитектуре был впервые предложен?", "a": ["Skip-соединения — в ResNet", "Конкатенация карт — в LeNet", "Dropout — в сети AlexNet", "Пулинг — в сети VGG"], "correct": 0, "explanation": "Сложение выхода блока с его входом (y=F(x)+x) — остаточные соединения ResNet (2015), облегчающие обучение очень глубоких сетей."}, {"id": "t4-018", "topic": "t4", "q": "Чем отличается приём передачи информации в DenseNet от ResNet?", "a": ["DenseNet конкатенирует по глубине", "DenseNet не использует свёртки", "DenseNet складывает, ResNet — нет", "Между ними нет различий"], "correct": 0, "explanation": "ResNet складывает вход с выходом блока; DenseNet конкатенирует выход с входными тензорами по глубине (с последующим снижением размерности свёрткой 1×1)."}, {"id": "t4-019", "topic": "t4", "q": "Какая архитектура считается первой классической СНС (1998)?", "a": ["LeNet", "AlexNet", "ResNet", "GoogLeNet"], "correct": 0, "explanation": "LeNet (1998) — первая классическая свёрточная сеть; AlexNet (2012) дал прорыв на ImageNet, ResNet — в 2015."}, {"id": "t4-020", "topic": "t4", "q": "Какая сеть в 2012 году дала прорыв в распознавании изображений (ImageNet)?", "a": ["AlexNet", "LeNet", "U-Net", "EfficientNet"], "correct": 0, "explanation": "AlexNet (2012) резко улучшила результаты на ImageNet, популяризировав глубокие СНС, ReLU и dropout."}, {"id": "t4-021", "topic": "t4", "q": "Чем известна архитектура VGGNet (2014–2015)?", "a": ["Глубина из малых ядер 3×3", "Полным отказом от свёрток", "Использованием только ядер 11×11", "Отсутствием полносвязных слоёв"], "correct": 0, "explanation": "VGG показала эффективность глубоких сетей из стандартных малых ядер 3×3, наращивая глубину при простой однородной структуре."}, {"id": "t4-022", "topic": "t4", "q": "Для каких задач характерна архитектура U-Net (2015)?", "a": ["Сегментация (кодер-декодер, skip)", "Машинный перевод текста между языками", "Генерация музыки и звука", "Сортировка чисел массива"], "correct": 0, "explanation": "U-Net — кодер-декодер с пробросом признаков (skip) между симметричными уровнями, применяется для сегментации (в т.ч. медицинских изображений)."}, {"id": "t4-023", "topic": "t4", "q": "Чем известна архитектура YOLO?", "a": ["Быстрая детекция за один проход", "Классификация без локализации", "Машинный перевод предложений", "Сжатие и кодирование изображений"], "correct": 0, "explanation": "YOLO (You Only Look Once) — однопроходный детектор объектов, предсказывающий рамки и классы за один прогон, что обеспечивает высокую скорость."}, {"id": "t4-024", "topic": "t4", "q": "Что такое перенос обучения (transfer learning) и тонкая настройка (fine-tuning)?", "a": ["Дообучение предобученной сети", "Обучение с нуля на случайных данных", "Удаление всех весов перед стартом", "Перенос файлов между дисками"], "correct": 0, "explanation": "Перенос обучения берёт сеть, обученную на большом наборе, и дообучает (fine-tune) её под целевую задачу — особенно полезно при малых данных (few-shot)."}, {"id": "t4-025", "topic": "t4", "q": "В чём суть враждебных (adversarial) атак на СНС?", "a": ["Незаметное изменение даёт ошибку", "Физическое повреждение сервера", "Удаление весов обученной сети", "Замедление процесса обучения"], "correct": 0, "explanation": "Adversarial-атака вносит малое, незаметное глазу возмущение, из-за которого классификатор ошибается, хотя исходное изображение распознавалось верно. Тема развивается с ~2013 года."}, {"id": "t4-026", "topic": "t4", "q": "Слова «adversarial» в контексте атак на сети в курсе трактуется как:", "a": ["Враждебные (не состязательные)", "Дружественные подсказки сети", "Случайные аппаратные сбои", "Методы регуляризации весов"], "correct": 0, "explanation": "Хотя «adversarial» переводят и как «состязательный», и как «враждебный», в данном случае речь именно о враждебных атаках на классификатор."}, {"id": "t4-027", "topic": "t4", "q": "Чем нормализация слоя (LayerNorm) отличается от пакетной (BatchNorm)?", "a": ["LN нормирует по признакам объекта", "LN нормирует по всему датасету", "LN не имеет обучаемых параметров", "Они полностью идентичны друг другу"], "correct": 0, "explanation": "LayerNorm считает статистики по признакам одного объекта (независимо от батча), тогда как BatchNorm — по мини-батчу; LN удобна для РНС и трансформеров."}, {"id": "t4-028", "topic": "t4", "q": "Почему Dropout после свёрточного слоя обычно нецелесообразен?", "a": ["Зашумляет карты признаков сети", "Он безвозвратно удаляет ядра свёртки", "Он полностью несовместим с ReLU", "Он применим только к входному слою"], "correct": 0, "explanation": "Обычный Dropout после свёртки делает карты признаков зашумлёнными; вместо него используют SpatialDropout2D, который отключает целые карты, снижая их корреляцию. Чаще Dropout ставят после Flatten."}, {"id": "t4-029", "topic": "t4", "q": "Что такое субдискретизация (downsampling/stride) в СНС?", "a": ["Прореживание выхода с шагом", "Увеличение разрешения карты", "Добавление новых каналов", "Нормировка значений тензора"], "correct": 0, "explanation": "Субдискретизация уменьшает пространственный размер (например, шаг 2 при пулинге 2×2 уменьшает размер вдвое по каждой координате)."}, {"id": "t4-030", "topic": "t4", "q": "Почему по мере углубления СНС типично увеличивают число фильтров?", "a": ["Растёт поле восприятия и число паттернов", "Чтобы заметно уменьшить число параметров", "Чтобы полностью убрать пулинг", "Это требование функции softmax"], "correct": 0, "explanation": "С глубиной поле восприятия растёт, и осмысленных паттернов становится больше — поэтому число фильтров обычно наращивают, компенсируя уменьшение пространственного размера."}, {"id": "t4-031", "topic": "t4", "q": "Что такое тензор в контексте СНС?", "a": ["Многомерный массив чисел", "Только двумерная матрица", "Скалярное произведение векторов", "Функция активации нейрона"], "correct": 0, "explanation": "Тензор — обобщение скаляра (ранг 0), вектора (ранг 1) и матрицы (ранг 2); в СНС работают в основном с тензорами ранга 3 (высота×ширина×каналы)."}, {"id": "t4-032", "topic": "t4", "q": "Какому тензору соответствует цветное изображение H×W с 3 каналами?", "a": ["Тензору ранга 3", "Тензору ранга 0", "Тензору ранга 1", "Тензору ранга 5"], "correct": 0, "explanation": "Изображение H×W×3 — это 3D-массив, то есть тензор ранга 3 (две пространственные координаты и канальная)."}, {"id": "t4-033", "topic": "t4", "q": "Чем перекрёстная корреляция (используемая в СНС) отличается от классической свёртки?", "a": ["Ядро не «переворачивается»", "Она не использует ядро вовсе", "Работает только с 1D-сигналами", "Она всегда коммутативна"], "correct": 0, "explanation": "Классическая свёртка обращает ядро ради коммутативности; в СНС применяют перекрёстную корреляцию (без обращения), но по традиции называют её «свёрткой»."}, {"id": "t4-034", "topic": "t4", "q": "По какой координате тензора при свёртке НЕ происходит суммирования со сдвигом (свёрточного скольжения)?", "a": ["По канальной координате (глубине)", "По высоте входного тензора", "По ширине входного тензора", "По всем трём координатам сразу"], "correct": 0, "explanation": "По глубине суммирование идёт без сдвига: глубина ядра равна глубине входа, поэтому результат для одного ядра — двумерная карта признаков."}, {"id": "t4-035", "topic": "t4", "q": "Какой пространственный размер выхода даёт свёртка с дополнением P₁,P₂ нулями (ядро M₁×M₂)?", "a": ["(N₁+P₁−M₁+1) × (N₂+P₂−M₂+1)", "(N₁−P₁) × (N₂−P₂) без ядра", "M₁ × M₂ (размер ядра)", "N₁·P₁ × N₂·P₂ (произвед.)"], "correct": 0, "explanation": "С учётом дополнения по P отсчётов: размер выхода (N₁+P₁−M₁+1)×(N₂+P₂−M₂+1). При подходящем P можно сохранить исходный размер (конгруэнтная свёртка)."}, {"id": "t4-036", "topic": "t4", "q": "Какие из перечисленного — метапараметры (а не обучаемые параметры) свёрточного слоя?", "a": ["Размеры/число ядер, шаги, padding", "Конкретные значения отсчётов фильтров", "Смещения свёрточных фильтров", "Выходные карты признаков"], "correct": 0, "explanation": "Обучаемые параметры — веса (отсчёты ядер) и смещения; метапараметры задаются заранее: число и размер фильтров, шаги и параметры дополнения."}, {"id": "t4-037", "topic": "t4", "q": "Что произойдёт с пространственным размером тензора при последовательных valid-свёртках без дополнения?", "a": ["Монотонно уменьшается до предела", "Будет неограниченно расти", "Останется полностью неизменным", "Сразу станет одномерным вектором"], "correct": 0, "explanation": "Каждая valid-свёртка уменьшает пространственный размер, поэтому без дополнения число слоёв ограничено; для углубления используют padding."}, {"id": "t4-038", "topic": "t4", "q": "Почему «крайние» отсчёты тензора при использовании padding нулями несут меньше информации?", "a": ["Зависят от нулевых дополнений", "Они вычисляются без весов", "Они всегда равны максимуму", "Они вообще не участвуют в свёртке"], "correct": 0, "explanation": "У границ значительная часть рецептивного поля приходится на нулевые дополнения, поэтому пространственно крайние значения менее содержательны."}, {"id": "t4-039", "topic": "t4", "q": "Как интерпретируется поточечная свёртка 1×1 как преобразование вектора-признака?", "a": ["Проекция в новое пространство", "Пространственный пулинг по карте", "Поворот входного изображения", "Нормализация активаций по батчу"], "correct": 0, "explanation": "Свёртка 1×1 в каждой точке делает линейную комбинацию каналов — это проекция канального вектора в новое пространство (аналог однослойного перцептрона), часто для изменения глубины."}, {"id": "t4-040", "topic": "t4", "q": "Что делает операция глобального max-пулинга (Global MaxPooling)?", "a": ["Вся карта → один максимум", "Удваивает размер карты вдвое", "Применяет softmax к карте", "Добавляет нулевой паддинг"], "correct": 0, "explanation": "Global MaxPooling берёт максимум по всей карте признаков, превращая каждую карту в одно число (часто перед классификатором вместо Flatten)."}, {"id": "t4-041", "topic": "t4", "q": "Что вычисляет average-пулинг?", "a": ["Локальное среднее в окне", "Локальный максимум в окне", "Сумму всех каналов карты", "Скалярное произведение с ядром"], "correct": 0, "explanation": "Average-пулинг усредняет значения в окне (независимо по каждой карте признаков); обучаемых параметров не имеет."}, {"id": "t4-042", "topic": "t4", "q": "Зачем нужна транспонированная свёртка (transposed convolution)?", "a": ["Увеличение размера (upsampling)", "Уменьшение числа каналов вдвое", "Нормализация активаций", "Вычисление функции потерь сети"], "correct": 0, "explanation": "Транспонированная свёртка («обратная» по эффекту) увеличивает пространственный размер карты — применяется в декодерах, генеративных и сегментационных сетях."}, {"id": "t4-043", "topic": "t4", "q": "Что такое «дырявая» (dilated/atrous) свёртка?", "a": ["Прорежённое ядро, большое поле", "Свёртка с полностью нулевыми весами", "Свёртка по одному каналу", "Свёртка без активации"], "correct": 0, "explanation": "Дырявая свёртка вставляет «промежутки» между отсчётами ядра, увеличивая рецептивное поле при том же числе параметров и без потери разрешения."}, {"id": "t4-044", "topic": "t4", "q": "В чём идея разделяемых по глубине свёрток (depthwise separable)?", "a": ["Разбить на поканальную и 1×1", "Объединить все каналы в один", "Полный отказ от свёрток", "Замена свёртки пулингом"], "correct": 0, "explanation": "Свёртку факторизуют на depthwise (отдельно по каждому каналу) и pointwise 1×1, что резко снижает число параметров и вычислений (используется в Xception, MobileNet)."}, {"id": "t4-045", "topic": "t4", "q": "Какую проблему обучения очень глубоких сетей решают остаточные (skip) соединения ResNet?", "a": ["Затухание градиента, путь y=F(x)+x", "Острую нехватку обучающих данных", "Слишком малое число параметров сети", "Отсутствие функции потерь сети"], "correct": 0, "explanation": "Skip-соединения дают градиенту «короткий путь» (y=F(x)+x), что предотвращает затухание и деградацию качества при увеличении глубины сети."}, {"id": "t4-046", "topic": "t4", "q": "Чем известна архитектура GoogLeNet / Inception?", "a": ["Inception-модули с параллельными ветвями", "Полным отказом от любых свёрток", "Использованием исключительно ядер 11×11", "Рекуррентными связями между слоями"], "correct": 0, "explanation": "GoogLeNet (Inception) применяет модули с параллельными ветвями (свёртки 1×1, 3×3, 5×5, пулинг) и свёртки 1×1 для снижения размерности и числа операций."}, {"id": "t4-047", "topic": "t4", "q": "Что отличает SpatialDropout2D от обычного Dropout в СНС?", "a": ["Отключает целые карты признаков", "Он удаляет ядра свёртки", "Работает только на входном слое", "Не используется при обучении"], "correct": 0, "explanation": "Обычный Dropout зашумляет карты поэлементно; SpatialDropout2D «выключает» целые карты признаков, снижая корреляцию между ними при сохранении пространственной структуры."}, {"id": "t5-001", "topic": "t5", "q": "Что такое рекуррентная нейронная сеть (РНС/RNN)?", "a": ["Сеть с обратной связью и состоянием", "Сеть без связей с фиксированным входом", "Сеть только из свёрточных слоёв", "Алгоритм поиска кратчайшего пути"], "correct": 0, "explanation": "РНС — сеть с обратной связью, отображающая последовательности входов в последовательности выходов; выход зависит и от входа, и от скрытого состояния, обновляемого во времени."}, {"id": "t5-002", "topic": "t5", "q": "По какой формуле простейшая РНС («Vanilla RNN») пересчитывает скрытое состояние?", "a": ["h(t)=f_h(W_hh·h(t−1)+W_xh·x(t)+b_h)", "h(t)=W·x(t) без зависимости от прошлого", "h(t)=max(x(t), h(t−1))", "h(t)=softmax(x(t)) по входу"], "correct": 0, "explanation": "Состояние: h(t)=f_h(W_hh·h(t−1)+W_xh·x(t)+b_h); выход: y(t)=f_y(W_hy·h(t)+b_y). Матрицы W и смещения b — обучаемые параметры."}, {"id": "t5-003", "topic": "t5", "q": "Что описывают матрицы W_xh, W_hh, W_hy в простейшей РНС?", "a": ["Вход–состояние, состояния, выход", "Три разные функции активации слоёв", "Размеры батча, эпохи и словаря", "Координаты операции пулинга"], "correct": 0, "explanation": "W_xh связывает вход с состоянием, W_hh — последовательные во времени скрытые состояния, W_hy — скрытое состояние с выходным вектором."}, {"id": "t5-004", "topic": "t5", "q": "Какую активацию выхода удобно выбрать, если РНС выдаёт слова/токены?", "a": ["Softmax размерности словаря", "ReLU на выходном слое", "Тождественную функцию выхода", "Знаковую функцию sign(x)"], "correct": 0, "explanation": "Для последовательности токенов/слов на выходе берут softmax размерности словаря; для вещественного выхода — ReLU, сигмоиду или тождественную функцию."}, {"id": "t5-005", "topic": "t5", "q": "Как строят глубокую РНС?", "a": ["Стек РНС: выход слоя → вход следующего", "Увеличивают только размер словаря модели", "Удаляют скрытое состояние сети", "Заменяют все слои на пулинг"], "correct": 0, "explanation": "Глубокая РНС — стек РНС: выходная последовательность одного слоя подаётся как вход следующего; каждая ячейка зависит от того же слоя в (t−1) и предыдущего слоя в t."}, {"id": "t5-006", "topic": "t5", "q": "Как называется алгоритм обучения РНС методом обратного распространения?", "a": ["Распространение во времени (BPTT)", "Прямое распространение ошибки вперёд", "Метод имитации отжига весов", "Случайный поиск по весам сети"], "correct": 0, "explanation": "BPTT (Back-Propagation Through Time): градиенты вычисляются рекурсивно, вклад шага t использует вклад шага t−1; время расчёта линейно по числу тактов."}, {"id": "t5-007", "topic": "t5", "q": "От чего, согласно курсу, существенно зависят проблемы исчезающего/взрывного градиента в РНС?", "a": ["От спектральной нормы матрицы W_hh", "От размера обучающего мини-батча", "От числа классов задачи", "От типа применяемого пулинга"], "correct": 0, "explanation": "Градиенты содержат члены ~(f'_h·W_hh)^T. Если спектральная норма W_hh <1 — градиент затухает, если >1 — взрывается; наибольшее по модулю собственное значение определяет поведение."}, {"id": "t5-008", "topic": "t5", "q": "Чему равна спектральная норма оператора?", "a": ["Максимальному сингулярному числу", "Следу матрицы оператора", "Определителю матрицы", "Сумме всех элементов матрицы оператора"], "correct": 0, "explanation": "Спектральная норма = максимальное сингулярное число; для нормального оператора она равна модулю наибольшего собственного значения."}, {"id": "t5-009", "topic": "t5", "q": "Какой простой эвристический приём применяют против взрывающихся градиентов?", "a": ["Усечение нормы градиента (clipping)", "Удаление скрытого состояния сети", "Увеличение скорости обучения вдвое", "Замена tanh на softmax"], "correct": 0, "explanation": "Gradient clipping ограничивает норму градиента сверху, предотвращая «взрыв»; более сложный путь — контроль спектрального радиуса W_hh."}, {"id": "t5-010", "topic": "t5", "q": "Какая архитектурная альтернатива явному контролю спектральной нормы предложена в курсе?", "a": ["Аддитивные обновления (как в LSTM)", "Полный отказ от скрытого состояния", "Замена РНС на слой пулинга", "Использование только одного такта"], "correct": 0, "explanation": "Вместо контроля нормы W_hh можно изменить архитектуру: применять аддитивные обновления состояния (LSTM/GRU), что облегчает передачу градиента во времени."}, {"id": "t5-011", "topic": "t5", "q": "Какое из перечисленного — преимущество простейших РНС?", "a": ["Размер модели не растёт с входом", "Очень высокая скорость вычислений", "Лёгкий доступ к далёкому прошлому", "Встроенный механизм внимания"], "correct": 0, "explanation": "Плюсы РНС: обработка входа любой длины, постоянный размер модели, общие веса (симметрия обработки). Минусы — медленность, забывание далёкого прошлого, проблемы градиента, отсутствие внимания."}, {"id": "t5-012", "topic": "t5", "q": "Какой недостаток простейших РНС связан с обработкой длинных последовательностей?", "a": ["Теряется информация о далёком прошлом", "Не может обрабатывать короткие входы", "Слишком большое число параметров", "Отсутствие функции активации"], "correct": 0, "explanation": "На практике РНС плохо «держит» давнюю информацию: сильнее влияют последние входы; плюс рекуррентные вычисления медленны и страдают от проблем градиента."}, {"id": "t5-013", "topic": "t5", "q": "Какова основная идея управляемых рекуррентных блоков (GRU)?", "a": ["Вентили: когда обновлять/сбрасывать", "Полностью убрать скрытое состояние сети", "Заменить рекуррентность свёрткой", "Использовать только softmax"], "correct": 0, "explanation": "GRU вводит управляемые вентили, чтобы избирательно запоминать важное и сбрасывать ненужное, обновляя состояние аддитивно (как в остаточных сетях) — это борется с затуханием градиента."}, {"id": "t5-014", "topic": "t5", "q": "Какие два вентиля используются в GRU?", "a": ["Сброса r(t) и обновления z(t)", "Входной, выходной, забывания", "Только вентиль внимания", "Вентиль свёртки и пулинга"], "correct": 0, "explanation": "GRU имеет вентиль сброса r(t) и вентиль обновления z(t), оба вычисляются через сигмоиду от входа и предыдущего состояния."}, {"id": "t5-015", "topic": "t5", "q": "Как в GRU вычисляется итоговое состояние через вентиль обновления z(t)?", "a": ["h(t)=z∘h(t−1)+(1−z)∘h̃(t)", "h(t)=z(t)·x(t) по входу", "h(t)=max(h(t−1), h̃(t))", "h(t)=softmax(z(t)) выхода"], "correct": 0, "explanation": "Состояние GRU — взвешенное (поэлементно) среднее старого состояния и кандидата: h(t)=z(t)∘h(t−1)+(1−z(t))∘h̃(t). При z=1 прошлое передаётся без изменений (долгосрочная память)."}, {"id": "t5-016", "topic": "t5", "q": "Что произойдёт в GRU, если элементы вентиля сброса r(t) близки к 0?", "a": ["Превращается в перцептрон от входа", "Состояние копирует прошлое целиком", "Сеть перестаёт обучаться вовсе", "Выход всегда становится нулевым"], "correct": 0, "explanation": "При r(t)→0 прошлое состояние «сбрасывается» и блок работает как перцептрон над текущим входом; при r(t)→1 — возвращается к стандартному правилу РНС. Вентиль сброса управляет краткосрочной памятью."}, {"id": "t5-017", "topic": "t5", "q": "Какую дополнительную структуру вводит LSTM по сравнению с простой РНС?", "a": ["Ячейку памяти c(t) рядом с h(t)", "Дополнительный свёрточный слой", "Позиционное кодирование входа", "Дополнительный слой пулинга"], "correct": 0, "explanation": "LSTM дополняет скрытое состояние h(t) ячейкой памяти c(t), которой управляют три вентиля."}, {"id": "t5-018", "topic": "t5", "q": "Какие три вентиля управляют ячейкой памяти в LSTM?", "a": ["Входной i, забывания f, выходной o", "Сброса, обновления и внимания слоёв", "Свёртки, пулинга и Flatten", "Кодера, декодера и маски"], "correct": 0, "explanation": "LSTM использует входной вентиль i (что помещать в ячейку), вентиль забывания f (когда сбрасывать) и выходной вентиль o (что читать из ячейки)."}, {"id": "t5-019", "topic": "t5", "q": "Как обновляется состояние ячейки c(t) в LSTM?", "a": ["c(t)=f∘c(t−1)+i∘c̃(t)", "c(t)=o(t)∘x(t)", "c(t)=softmax(c(t−1))", "c(t)=max(c(t−1), x(t))"], "correct": 0, "explanation": "Новое состояние ячейки: c(t)=f(t)∘c(t−1)+i(t)∘c̃(t). При f=1, i=0 информация сохраняется неопределённо долго — реализуется долгосрочная память."}, {"id": "t5-020", "topic": "t5", "q": "Как в LSTM вычисляется скрытое состояние/выход h(t)?", "a": ["h(t)=o(t)∘tanh(c(t))", "h(t)=i(t)∘c(t−1)", "h(t)=f(t)∘x(t)", "h(t)=softmax(c(t)) по ячейке"], "correct": 0, "explanation": "h(t)=o(t)∘tanh(c(t)) — выходной вентиль определяет, какую часть преобразованной ячейки «прочитать». h(t) — одновременно выход и состояние следующего шага."}, {"id": "t5-021", "topic": "t5", "q": "Что в LSTM играет роль долгосрочной, а что краткосрочной памяти?", "a": ["c(t) — долгая, h(t) — короткая", "h(t) — долгая, c(t) — короткая", "Обе только краткосрочные", "Память полностью отсутствует"], "correct": 0, "explanation": "Вектор ячейки c(t) работает как долгосрочная память, а h(t) (то, что только что выведено) — как краткосрочная. Отсюда название Long Short-Term Memory."}, {"id": "t5-022", "topic": "t5", "q": "Гарантирует ли LSTM полное отсутствие проблемы исчезающих/взрывающихся градиентов?", "a": ["Нет, но упрощает передачу во времени", "Да, полностью устраняет проблему", "Нет, и ухудшает по сравнению с РНС", "Проблема к LSTM неприменима"], "correct": 0, "explanation": "LSTM не гарантирует отсутствие проблем градиента, но облегчает передачу информации во времени (аналогия со skip-соединениями ResNet)."}, {"id": "t5-023", "topic": "t5", "q": "Что появилось раньше исторически — GRU или LSTM?", "a": ["LSTM (1997), GRU позже (2014)", "GRU появился раньше, LSTM позже", "Появились одновременно", "Оба появились в 2017 году"], "correct": 0, "explanation": "LSTM предложена Хохрайтером и Шмидхубером в 1997 г.; GRU — более простой вариант (Cho и др., 2014), появившийся почти на 20 лет позже."}, {"id": "t5-024", "topic": "t5", "q": "Что означает операция «∘» (кружок) в формулах GRU/LSTM?", "a": ["Поэлементное умножение (Адамар)", "Матричное умножение векторов", "Свёртку двух векторов", "Скалярное произведение векторов"], "correct": 0, "explanation": "Символ ∘ — произведение Адамара (поэлементное умножение векторов одинаковой размерности)."}, {"id": "t5-025", "topic": "t5", "q": "Какой недостаток простых РНС устраняет механизм внимания (attention)?", "a": ["Нет прямого доступа к входу", "Слишком быстрые вычисления сети", "Полное отсутствие весов", "Избыток скрытых состояний сети"], "correct": 0, "explanation": "Простые РНС сжимают всю историю в одно состояние и теряют доступ к давним элементам; механизм внимания позволяет напрямую взвешивать все элементы входа."}, {"id": "t5-026", "topic": "t5", "q": "Что такое жадный (greedy) алгоритм генерации последовательности?", "a": ["Берёт самый вероятный токен", "Случайный выбор любого токена", "Перебор всех последовательностей", "Берёт наименее вероятный токен"], "correct": 0, "explanation": "Жадная генерация на каждом шаге берёт самый вероятный токен (argmax). Просто, но не гарантирует глобально лучшую последовательность."}, {"id": "t5-027", "topic": "t5", "q": "Как параметр «температуры» влияет на генерацию текста?", "a": ["Выше T — разнообразнее, ниже — острее", "Меняет число слоёв сети", "Управляет скоростью обучения сети", "Задаёт максимальный размер словаря"], "correct": 0, "explanation": "Температура масштабирует логиты перед softmax: высокая — более разнообразный (рискованный) текст, низкая — более детерминированный и «уверенный»."}, {"id": "t5-028", "topic": "t5", "q": "В чём суть поиска по лучу (Beam Search) при генерации?", "a": ["Держит k лучших гипотез параллельно", "Берёт ровно один токен, без возврата", "Полный перебор всех вариантов", "Случайный выбор по температуре"], "correct": 0, "explanation": "Beam Search хранит k лучших частичных гипотез на каждом шаге, расширяя их, что даёт лучшую итоговую последовательность, чем жадный выбор, без полного перебора."}, {"id": "t5-029", "topic": "t5", "q": "Что делает генерация с отбрасыванием маловероятных токенов?", "a": ["Оставляет только вероятные токены", "Всегда берёт самый редкий токен", "Удваивает длину последовательности", "Полностью отключает softmax"], "correct": 0, "explanation": "Сэмплирование с отсечением (top-k / top-p) исключает маловероятные токены, снижая шанс бессмысленных продолжений при сохранении разнообразия."}, {"id": "t5-030", "topic": "t5", "q": "Для каких задач с изображениями применяют РНС, согласно курсу?", "a": ["Описание, VQA и навигация", "Только сжатие изображений", "Только операция свёртки карт", "Только операция пулинга карт"], "correct": 0, "explanation": "РНС используют для генерации описаний изображений и видео (captioning), ответов на вопросы по изображению (VQA) и навигации."}, {"id": "t5-031", "topic": "t5", "q": "Что является скрытым состоянием РНС и какую роль оно играет?", "a": ["Вектор h(t) — память о прошлом", "Вектор весов выходного слоя сети", "Размер словаря модели", "Скорость обучения сети"], "correct": 0, "explanation": "Скрытое состояние h(t) переносит информацию от прошлых шагов к будущим — это «память» сети, обновляемая на каждом такте."}, {"id": "t5-032", "topic": "t5", "q": "Что означает обозначение x(t) с постфиксом (t) в формулах РНС?", "a": ["Вход в дискретный момент t", "Транспонирование вектора x", "t-я степень вектора x", "Производная x по времени"], "correct": 0, "explanation": "Постфикс (t) обозначает значение в дискретный момент времени t=0,1,…,T−1, поскольку входы подаются последовательно."}, {"id": "t5-033", "topic": "t5", "q": "Какой режим работы РНС соответствует задаче классификации последовательности (один выход на всю последовательность)?", "a": ["Many-to-one (входы → один выход)", "One-to-one (один к одному)", "One-to-many (один ко многим)", "Полносвязный режим без состояния"], "correct": 0, "explanation": "Классификация последовательности — режим «многие-к-одному»: сеть читает всю последовательность и выдаёт один итоговый вектор (например, класс)."}, {"id": "t5-034", "topic": "t5", "q": "Почему говорят, что архитектура РНС решает проблему ограниченного контекста?", "a": ["Через состояние видит далёкое прошлое", "Хранит всю последовательность явно в памяти", "Не использует прошлые входы", "Размер модели растёт с входом"], "correct": 0, "explanation": "Через рекуррентное состояние РНС теоретически может учитывать сколь угодно давнюю информацию, в отличие от моделей с фиксированным окном контекста."}, {"id": "t5-035", "topic": "t5", "q": "Почему в простых РНС применяются одни и те же веса на каждом временном шаге?", "a": ["Симметрия и постоянный размер модели", "Чтобы ускорить работу функции softmax", "Это требование слоя пулинга", "Чтобы отключить активацию"], "correct": 0, "explanation": "Разделение весов по времени — ключевая идея РНС: одинаковая обработка каждого элемента и постоянный размер модели независимо от длины последовательности."}, {"id": "t5-036", "topic": "t5", "q": "Какой главный недостаток скорости у РНС по сравнению с трансформерами?", "a": ["Вычисления строго последовательны", "Слишком много памяти на ядра свёртки", "Они не используют градиент", "Слишком много голов внимания"], "correct": 0, "explanation": "Из-за зависимости h(t) от h(t−1) шаги нельзя выполнять параллельно — это делает РНС медленными в сравнении с параллельным вниманием трансформера."}, {"id": "t5-037", "topic": "t5", "q": "Почему в простой РНС последние входы влияют на результат сильнее давних?", "a": ["Сигнал о далёком прошлом затухает", "Веса последних шагов заметно больше", "Softmax обнуляет старые входы", "Это особенность слоя пулинга"], "correct": 0, "explanation": "При прохождении через многие шаги сигнал и градиент от давних входов затухают, поэтому на практике сильнее влияют недавние элементы последовательности."}, {"id": "t5-038", "topic": "t5", "q": "Что такое вентиль (gate) в GRU/LSTM?", "a": ["Вектор в (0,1), управляет потоком", "Дополнительный слой свёртки", "Это функция потерь сети", "Матрица позиционного кодирования"], "correct": 0, "explanation": "Вентиль — вектор из сигмоиды со значениями в (0,1); поэлементным умножением он регулирует, какую долю информации пропустить/сохранить/сбросить."}, {"id": "t5-039", "topic": "t5", "q": "Какую активацию используют для вычисления самих вентилей в GRU/LSTM и почему?", "a": ["Сигмоиду — выход в (0,1)", "ReLU — для разрежённости", "Softmax — нормировка по словарю", "tanh — для центрирования значений"], "correct": 0, "explanation": "Вентили считаются сигмоидой, дающей значения в (0,1), что естественно интерпретируется как степень открытия вентиля; кандидат состояния обычно берётся через tanh."}, {"id": "t5-040", "topic": "t5", "q": "Какое полезное свойство сигмоиды σ используется в выкладках GRU?", "a": ["1 − σ(x) = σ(−x)", "σ(x) = x² (квадрат)", "σ(x) всегда > 1", "σ(x) = tanh(x)"], "correct": 0, "explanation": "Свойство 1−σ(x)=σ(−x) удобно при работе с вентилями обновления, где встречаются и z, и (1−z)."}, {"id": "t5-041", "topic": "t5", "q": "Зачем кандидат нового состояния в GRU/LSTM пропускают через tanh?", "a": ["Держать значения в (−1, 1)", "Чтобы получить вероятности", "Чтобы обнулить отрицательные", "Чтобы увеличить словарь"], "correct": 0, "explanation": "tanh центрирует и ограничивает кандидата состояния диапазоном (−1,1), что стабилизирует динамику скрытых состояний."}, {"id": "t5-042", "topic": "t5", "q": "Что общего между аддитивным обновлением состояния в LSTM/GRU и остаточными сетями (ResNet)?", "a": ["Аддитивный путь облегчает градиент", "Оба используют свёртки 1×1 в блоках", "Оба применяют пулинг", "Оба не имеют параметров"], "correct": 0, "explanation": "Аддитивные обновления (c(t)=f∘c(t−1)+…) создают «короткий путь» для градиента, аналогично skip-соединениям ResNet, смягчая затухание."}, {"id": "t5-043", "topic": "t5", "q": "Сколько вентилей у GRU и сколько у LSTM?", "a": ["GRU — 2, LSTM — 3 вентиля", "GRU — 3, LSTM — 2 вентиля", "У обоих по 4 вентиля", "У обоих по одному вентилю"], "correct": 0, "explanation": "GRU использует два вентиля (сброс r, обновление z), LSTM — три (входной i, забывания f, выходной o) плюс отдельную ячейку памяти c."}, {"id": "t5-044", "topic": "t5", "q": "В архитектуре «энкодер-декодер» для перевода что передаётся от энкодера к декодеру в простейшем варианте?", "a": ["Контекстный вектор состояния", "Только первый входной токен", "Матрицу позиционного кодирования входа", "Веса выходного слоя сети"], "correct": 0, "explanation": "Энкодер сжимает входную последовательность в контекстный вектор (последнее состояние), который инициализирует декодер; механизм внимания снимает узкое место этого единственного вектора."}, {"id": "t5-045", "topic": "t5", "q": "Что произойдёт при генерации текста с очень низкой температурой (→0)?", "a": ["Генерация почти детерминирована", "Текст станет максимально случайным", "Модель перестанет работать", "Увеличится размер словаря"], "correct": 0, "explanation": "Низкая температура «заостряет» распределение, и выбор сводится к самому вероятному токену — поведение приближается к жадному декодированию."}, {"id": "t6-001", "topic": "t6", "q": "В каком году и в какой работе был предложен трансформер?", "a": ["В 2017, «Attention is all you need»", "В 1997, Хохрайтер и Шмидхубер", "В 2012 году, в работе по AlexNet", "В 2020 году, в работе по BERT"], "correct": 0, "explanation": "Трансформер предложен в 2017 г. в статье «Attention is all you need» коллективом авторов, в основном из подразделений Google."}, {"id": "t6-002", "topic": "t6", "q": "Из каких двух основных частей состоит классический трансформер?", "a": ["Кодер (encoder) и декодер (decoder)", "Свёрточная и рекуррентная части сети", "Только из стека слоёв пулинга", "Из энкодера и дискриминатора"], "correct": 0, "explanation": "Трансформер состоит из похожих по структуре, но независимых частей: кодера (преобразует вход в представления) и декодера (последовательно синтезирует выход)."}, {"id": "t6-003", "topic": "t6", "q": "Как задаётся базовый блок Scaled Dot-Product Attention (SDPA)?", "a": ["SoftMax(Kqᵀ/√d)·V — комбинация значений", "Сумма ключей без нормировки", "Произведение значений на единичную матрицу", "Среднее всех запросов сразу"], "correct": 0, "explanation": "SDPA(q,K,V)=SoftMax(Kqᵀ/√d)·V — взвешенная (выпуклая) комбинация значений V, где веса вычисляются softmax от масштабированных скалярных произведений ключей и запроса."}, {"id": "t6-004", "topic": "t6", "q": "Зачем в SDPA скалярные произведения делят на √d?", "a": ["Масштаб: softmax не теряет градиент", "Чтобы добавить обучаемые параметры", "Чтобы увеличить размерность выхода", "Это требование позиционных кодов"], "correct": 0, "explanation": "Деление на √d (масштабирование) удерживает аргументы softmax в разумном диапазоне при больших размерностях, предотвращая насыщение и затухание градиентов."}, {"id": "t6-005", "topic": "t6", "q": "Что в SDPA интерпретируется как «ключи», «значения» и «запросы»?", "a": ["K — ключи, V — значения, Q — запросы", "K — запросы, Q — ключи, V — это маски", "Все три — одинаковые маски", "K и V — смещения, Q — веса"], "correct": 0, "explanation": "K (Keys) — ключи, V (Values) — значения (n пар ключ-значение), Q (Queries) — запросы; внимание сопоставляет запросы с ключами и агрегирует значения."}, {"id": "t6-006", "topic": "t6", "q": "Какой указан недостаток «голого» SDPA?", "a": ["Отсутствие обучаемых параметров", "Слишком много параметров", "Невозможность дифференцирования", "Зависимость от длины обучения"], "correct": 0, "explanation": "SDPA сам по себе не содержит обучаемых параметров; параметризацию добавляет многоголовое внимание (MHA) через матрицы проекций."}, {"id": "t6-007", "topic": "t6", "q": "Что такое многоголовое внимание (Multi-Head Attention, MHA)?", "a": ["h голов SDPA + линейное объединение", "Один блок SDPA без всяких проекций", "Свёртка входа с h ядрами", "Пулинг по h окнам сразу"], "correct": 0, "explanation": "MHA проецирует Q,K,V h разными обучаемыми матрицами в меньшие пространства, применяет SDPA к каждой «голове» и склеивает результаты через выходную матрицу W^O."}, {"id": "t6-008", "topic": "t6", "q": "Какие параметры h, d, d_K использовались в оригинальной работе по трансформеру?", "a": ["h=8, d=512, d_K=d_V=64", "h=1, d=64, d_K=512", "h=16, d=2048, d_K=128", "h=6, d=256, d_K=256"], "correct": 0, "explanation": "В оригинале: 8 голов, размерность модели d=512, размерности ключей/значений d_K=d_V=64 (так что d_K·h=d)."}, {"id": "t6-009", "topic": "t6", "q": "Какое свойство MHA отмечено в курсе относительно числа голов?", "a": ["Параметры не зависят от числа голов", "Параметры растут квадратично с головами", "Размер словаря растёт с числом голов", "Число голов равно числу слоёв"], "correct": 0, "explanation": "Благодаря соотношению размерностей (d_K·h=d_V·h=d) общее число обучаемых параметров MHA не зависит от числа голов; разные головы улавливают разные «аспекты» данных."}, {"id": "t6-010", "topic": "t6", "q": "Зачем в декодере используется маскированное внимание (Masked MHA)?", "a": ["Исключить будущие токены из расчёта", "Чтобы удалить позиционное кодирование", "Чтобы увеличить число голов внимания", "Чтобы нормировать значения"], "correct": 0, "explanation": "Маскирование запрещает позиции «заглядывать» в будущие токены: при предсказании элемента доступна только его предыстория — это нужно для авторегрессионной генерации."}, {"id": "t6-011", "topic": "t6", "q": "Как технически реализуется маскирование в Masked SDPA?", "a": ["В softmax добавляют −∞ для запрещённых", "Запрещённые значения умножают на два", "Маскирование удаляет всю матрицу V", "Используется average pooling"], "correct": 0, "explanation": "Запрещённым позициям перед softmax присваивают очень большое отрицательное значение (−∞), так что после softmax их веса становятся нулевыми."}, {"id": "t6-012", "topic": "t6", "q": "Как формируются входные эмбеддинги x^in в трансформере 2017 года?", "a": ["x^in=W^in·b^in (b — one-hot токена)", "x^in = softmax(b^in) по токену", "x^in = свёртка входного изображения", "x^in = случайный шум входа"], "correct": 0, "explanation": "Входной индикаторный (one-hot) вектор токена умножается на матрицу эмбеддингов W^in, выбирая столбец-эмбеддинг соответствующего слова."}, {"id": "t6-013", "topic": "t6", "q": "Зачем трансформеру нужно позиционное кодирование?", "a": ["Внимание не учитывает порядок токенов", "Чтобы уменьшить число параметров сети", "Чтобы заменить функцию потерь", "Чтобы выполнять операцию пулинга"], "correct": 0, "explanation": "Внимание инвариантно к перестановке входов, поэтому к эмбеддингам добавляют позиционные коды p_i, несущие информацию о позиции в последовательности."}, {"id": "t6-014", "topic": "t6", "q": "Какими функциями задаётся позиционное кодирование в оригинальном трансформере?", "a": ["Синусами и косинусами разных частот", "Только линейной функцией от позиции", "Случайными обучаемыми числами", "Функцией softmax от позиции"], "correct": 0, "explanation": "Позиционные коды используют синусы (чётные компоненты) и косинусы (нечётные) с геометрически меняющимися частотами; R=10000 — максимальная длина последовательности."}, {"id": "t6-015", "topic": "t6", "q": "Как позиционная информация комбинируется с эмбеддингами входа?", "a": ["Складываются: x_i = x_i^in + p_i", "Конкатенация с удвоением размера", "Перемножаются поэлементно", "Подаётся в отдельную сеть"], "correct": 0, "explanation": "Позиционный код p_i просто прибавляется к эмбеддингу: x_i = x_i^in + p_i (размерности совпадают)."}, {"id": "t6-016", "topic": "t6", "q": "Что представляет собой позиционная сеть прямого распространения (PositionWise FFN)?", "a": ["Двухслойная FFN на каждую позицию", "Рекуррентный слой сети РНС", "Свёрточный слой ядром 3×3", "Блок пространственного пулинга"], "correct": 0, "explanation": "PW-FFN — двухслойная сеть с ReLU на первом слое и тождественной функцией на втором, применяемая независимо и с общими параметрами к каждой позиции."}, {"id": "t6-017", "topic": "t6", "q": "Какова размерность скрытого слоя d_ff в FFN оригинального трансформера?", "a": ["d_ff = 2048 (= 4·d)", "d_ff = 64", "d_ff = 512", "d_ff = 25000 (словарь)"], "correct": 0, "explanation": "Внутренний слой FFN имеет размерность d_ff=2048, что вчетверо больше размерности модели d=512."}, {"id": "t6-018", "topic": "t6", "q": "Какие два ключевых приёма используются в основном блоке кодера трансформера?", "a": ["Внимание (MHA) и skip-связи", "Свёртка и операция макс-пулинга", "Рекуррентность и метод dropout", "Beam search и температура"], "correct": 0, "explanation": "Блок кодера: MHA + остаточные (skip) связи из ResNet + нормализация слоя (LN); затем PW-FFN снова со skip-связью и LN."}, {"id": "t6-019", "topic": "t6", "q": "Сколько основных блоков N в базовом кодере и декодере трансформера?", "a": ["N = 6", "N = 1", "N = 12", "N = 512"], "correct": 0, "explanation": "В базовом варианте и кодер, и декодер состоят из N=6 одинаковых по структуре блоков (с разными параметрами)."}, {"id": "t6-020", "topic": "t6", "q": "Чем структурно отличается блок декодера от блока кодера?", "a": ["Маск. самовнимание и кросс-внимание", "В декодере отсутствует блок FFN", "В декодере нет нормализации слоёв", "Декодер использует свёртки вместо внимания"], "correct": 0, "explanation": "Блок декодера содержит три подслоя: маскированное самовнимание MMHA(Q=Y,K=Y,V=Y), кросс-внимание MHA(Q=Ỹ,K=E,V=E) к представлениям кодера и PW-FFN — каждый со skip+LN."}, {"id": "t6-021", "topic": "t6", "q": "Как в режиме инференса декодер синтезирует выходную последовательность?", "a": ["Поэлементно, до токена [EOS]", "Всю последовательность за один проход", "Случайной выборкой без остановки", "Через обратное распространение"], "correct": 0, "explanation": "В инференсе декодер запускается по одному токену за раз (авторегрессионно), добавляя предсказанные токены ко входу, пока не сгенерирует [EOS]."}, {"id": "t6-022", "topic": "t6", "q": "Чем режим обучения декодера отличается от режима применения?", "a": ["Подаётся вся верная последовательность", "При обучении нет функции потерь вовсе", "При обучении нет маскирования", "При обучении декодер не нужен"], "correct": 0, "explanation": "При обучении используют всю истинную последовательность для декодера сразу (с маскированием), сравнивая выходные распределения с истинными токенами — это ускоряет обучение (teacher forcing)."}, {"id": "t6-023", "topic": "t6", "q": "Что делает функция BinMax на выходе декодера в режиме инференса?", "a": ["Вероятности → one-hot (argmax)", "Усредняет все вероятности токенов", "Применяет функцию ReLU к выходу", "Нормирует вектор по L2-норме"], "correct": 0, "explanation": "BinMax формирует индикаторный (one-hot) вектор: единица ставится на позиции наибольшей вероятности (argmax g_m), остальные — нули."}, {"id": "t6-024", "topic": "t6", "q": "Чем отличаются варианты Post-LN и Pre-LN трансформера?", "a": ["Post-LN: LN(x+F); Pre-LN: x+F(LN)", "Pre-LN не использует skip-связи вовсе", "Post-LN убирает блок внимания", "Они полностью идентичны"], "correct": 0, "explanation": "В оригинале LN применялась после агрегации (Post-LN). В Pre-LN нормализация ставится перед подблоком F: x*=x+F(LN(x)), что часто стабильнее при обучении."}, {"id": "t6-025", "topic": "t6", "q": "На какой части трансформера основана модель BERT и почему?", "a": ["На кодере — двунаправленный контекст", "На декодере — однонаправленная генерация", "На свёрточных слоях сети", "На рекуррентных блоках РНС"], "correct": 0, "explanation": "BERT (Bidirectional Encoder Representations from Transformers) использует кодер, чтобы учитывать двунаправленный контекст (внимание ко всем токенам предложения)."}, {"id": "t6-026", "topic": "t6", "q": "Какие две задачи предобучения предложены в BERT?", "a": ["MLM (маскирование) и NSP", "Beam search и температура", "Свёртка и операция макс-пулинга", "Регрессия и кластеризация данных"], "correct": 0, "explanation": "BERT обучается на MLM (предсказание случайно замаскированных токенов) и NSP (предсказание, следует ли одно предложение за другим)."}, {"id": "t6-027", "topic": "t6", "q": "Какую часть трансформера использует модель GPT?", "a": ["Только декодер", "Только кодер", "И кодер, и декодер", "Свёрточный энкодер"], "correct": 0, "explanation": "GPT использует исключительно декодер (без блоков кросс-внимания к кодеру), решая задачу языкового моделирования — предсказания следующего слова."}, {"id": "t6-028", "topic": "t6", "q": "В чём суть концепции генеративного предобучения (Generative Pre-Training) в GPT?", "a": ["Предобучение + тонкая настройка", "Обучение только на размеченных данных", "Полный отказ от обучения", "Обучение вниманием без потерь"], "correct": 0, "explanation": "GPT вводит двухэтапный подход: предобучение (самообучение на больших неразмеченных текстах через предсказание следующего токена) и затем fine-tuning под конкретные задачи."}, {"id": "t6-029", "topic": "t6", "q": "Что такое перплексия (perplexity, PPL) при оценке генерации текста?", "a": ["Как хорошо модель предсказывает", "Число параметров всей модели", "Скорость обучения сети", "Количество голов внимания в MHA"], "correct": 0, "explanation": "Перплексия — мера качества языковой модели, связанная с обратным геометрическим средним предсказанных вероятностей токенов; меньшая PPL означает более уверенное и точное предсказание."}, {"id": "t6-030", "topic": "t6", "q": "Какое преимущество трансформеров перед РНС является ключевым?", "a": ["Параллельность и доступ ко всем словам", "Всегда строго меньшее число параметров", "Полное отсутствие функции потерь", "Полный отказ от обучения"], "correct": 0, "explanation": "В отличие от последовательных РНС, трансформер обрабатывает все позиции параллельно и через внимание напрямую связывает любые токены, лучше улавливая дальние зависимости."}, {"id": "t6-031", "topic": "t6", "q": "Сколько примерно обучаемых параметров во всём базовом трансформере (по методичке)?", "a": ["Порядка 68 млн", "Порядка 1 тыс.", "Порядка 5 млрд", "Порядка 500 штук"], "correct": 0, "explanation": "По расчётам методички: кодер ~31,7 млн + декодер ~38 млн параметров, итого порядка 68 млн обучаемых параметров в базовом трансформере."}, {"id": "t6-032", "topic": "t6", "q": "Что трансформер-кодер делает с входной последовательностью из n векторов размерности d?", "a": ["n выходов той же размерности d", "Сжимает всё в один скаляр", "Удлиняет до m>n токенов сразу", "Превращает вход в изображение"], "correct": 0, "explanation": "Кодер отображает n входных d-мерных векторов в n выходных представлений (e₁..eₙ) той же размерности d, обогащённых контекстом через самовнимание."}, {"id": "t6-033", "topic": "t6", "q": "Что в SDPA выступает «коэффициентами смешивания» векторов-значений V?", "a": ["Веса softmax от Kqᵀ/√d", "Сами значения V напрямую", "Позиционные коды входа", "Выходная матрица W^O"], "correct": 0, "explanation": "Выход внимания — выпуклая комбинация значений V; коэффициенты задаёт softmax от масштабированных скалярных произведений запроса с ключами."}, {"id": "t6-034", "topic": "t6", "q": "Каким свойством обладает SDPA относительно перестановки строк ключей и значений (одинаковой перестановки π)?", "a": ["Инвариантность к перестановке K,V", "Результат меняет знак", "Результат полностью обнуляется", "Размерность результата удваивается"], "correct": 0, "explanation": "Одновременная перестановка пар (ключ, значение) не меняет результат внимания — SDPA инвариантно к порядку пар ключ-значение (потому и нужно позиционное кодирование)."}, {"id": "t6-035", "topic": "t6", "q": "Что происходит с результатом SDPA при перестановке строк запросов Q?", "a": ["Строки результата переставляются", "Результат вообще никак не меняется", "Результат полностью обнуляется", "Меняется размерность ключей"], "correct": 0, "explanation": "Перестановка запросов π(Q) приводит к той же перестановке строк результата: SDPA(π(Q),K,V)=π(SDPA(Q,K,V)) — эквивариантность по запросам."}, {"id": "t6-036", "topic": "t6", "q": "Зачем каждой «голове» в MHA свои матрицы проекций W^Q, W^K, W^V?", "a": ["Чтобы головы учили разные аспекты", "Чтобы снизить размерность модели до 1", "Чтобы убрать позиционные коды", "Чтобы заменить собой блок FFN"], "correct": 0, "explanation": "Параметризованные проекции позволяют каждой голове рассматривать свой подвид связей (синтаксис, семантику и т.п.); результаты голов объединяются линейно через W^O."}, {"id": "t6-037", "topic": "t6", "q": "Какое соотношение размерностей выполняется в MHA (d_K, d_V, h, d)?", "a": ["d_K·h = d_V·h = d", "d_K = d_V = d·h", "h = d (равны)", "d_K = d² (квадрат)"], "correct": 0, "explanation": "Размерности подпространств голов подобраны так, что d_K·h=d_V·h=d (в оригинале h=8, d_K=d_V=64, d=512), поэтому общее число параметров не зависит от числа голов."}, {"id": "t6-038", "topic": "t6", "q": "Какая размерность у результата MHA(Q,K,V) при m запросах?", "a": ["m × d", "m × h", "d × d", "n × vocab"], "correct": 0, "explanation": "После объединения голов и умножения на W^O результат MHA имеет размерность m×d — столько же строк, сколько запросов, и размерность модели d."}, {"id": "t6-039", "topic": "t6", "q": "Что именно «маскируется» в Masked MHA декодера?", "a": ["Будущие позиции последовательности", "Все позиции, кроме самой первой", "Позиционные коды на входе", "Веса слоя FFN декодера"], "correct": 0, "explanation": "Маска запрещает позиции учитывать будущие токены: при предсказании t-го элемента доступны только элементы до t — это обеспечивает корректную авторегрессию."}, {"id": "t6-040", "topic": "t6", "q": "Почему позиционная FFN называется «позиционной» (position-wise)?", "a": ["Применяется к каждой позиции", "Зависит от номера текущей эпохи", "Работает только с первой позицией", "Задаёт сами позиционные коды"], "correct": 0, "explanation": "PW-FFN обрабатывает каждый позиционный вектор отдельно, но одними и теми же весами W₁,W₂ — отсюда «по-позиционная»."}, {"id": "t6-041", "topic": "t6", "q": "Какова формула позиционной сети FFN в трансформере?", "a": ["FFN(x)=W₂·ReLU(W₁x+b₁)+b₂", "FFN(x)=softmax(W·x+b)", "FFN(x)=x+p (сложение)", "FFN(x)=tanh(Wx+b)"], "correct": 0, "explanation": "Двухслойная сеть с ReLU на первом слое и тождественной функцией на втором: FFN(x)=W₂·ReLU(W₁x+b₁)+b₂, где d_ff=2048."}, {"id": "t6-042", "topic": "t6", "q": "Почему позиционные коды на основе синусов/косинусов удобны для разных длин последовательностей?", "a": ["Работают для любой длины", "Обучаются под фиксированную длину", "Зависят от размера батча", "Одинаковы для всех позиций"], "correct": 0, "explanation": "Синусоидальные коды — фиксированная функция позиции и частоты, поэтому естественно обобщаются на последовательности произвольной (в т.ч. большей) длины."}, {"id": "t6-043", "topic": "t6", "q": "Что подаётся на вход декодера в режиме обучения (teacher forcing)?", "a": ["Вся верная последовательность", "Только выход энкодера E", "Случайные токены на входе", "Ничего, декодер вообще не учится"], "correct": 0, "explanation": "При обучении декодеру дают всю верную последовательность (сдвинутую на один), а маскирование не даёт «подглядывать» вперёд — это ускоряет обучение по сравнению с пошаговой генерацией."}, {"id": "t6-044", "topic": "t6", "q": "Каким токеном начинается и заканчивается генерация декодера?", "a": ["Старт [SOS], стоп при [EOS]", "Старт [EOS], конец [SOS]", "Старт и конец [MASK]", "Без специальных токенов"], "correct": 0, "explanation": "Генерация стартует со стартового токена [SOS] и продолжается, пока декодер не предскажет токен конца последовательности [EOS]."}, {"id": "t6-045", "topic": "t6", "q": "Почему в BERT возможно двунаправленное внимание, а в GPT — только однонаправленное?", "a": ["Кодер видит весь контекст, GPT — нет", "BERT вообще не использует внимание", "GPT видит будущее, а BERT — нет", "Различие лишь в размере словаря"], "correct": 0, "explanation": "Кодер BERT не маскирует позиции и учитывает контекст с обеих сторон; декодер GPT маскирует будущее, оставляя для каждого токена лишь предысторию (нужно для генерации)."}, {"id": "t6-046", "topic": "t6", "q": "Что устраняется в блоке декодера GPT по сравнению с классическим декодером трансформера?", "a": ["Кросс-внимание к кодеру (его нет)", "Позиционное кодирование на входе", "Маскированное самовнимание блока", "Полносвязная сеть FFN"], "correct": 0, "explanation": "GPT отказывается от энкодера, поэтому из блока декодера убирается кросс-внимание к выходу кодера; остаётся маскированное самовнимание и FFN."}, {"id": "t6-047", "topic": "t6", "q": "Чем меньше перплексия языковой модели, тем:", "a": ["Лучше предсказывает (точнее)", "Тем хуже сама модель", "Тем больше у неё параметров", "Тем выше скорость обучения"], "correct": 0, "explanation": "Перплексия обратно связана с предсказанными вероятностями токенов: меньшая PPL означает, что модель присваивает истинным токенам более высокие вероятности — лучшее качество."}, {"id": "t7-001", "topic": "t7", "q": "Какую функцию активации используют в последнем слое НС при решении задачи бинарной классификации?", "a": ["сигмоида", "тождественная", "ReLU", "softmax", "ELU", "swish"], "correct": [0], "explanation": "Для бинарной классификации в выходном слое с одним нейроном берут сигмоиду — она даёт вероятность класса в (0,1)."}, {"id": "t7-002", "topic": "t7", "q": "Что можно реализовать в виде одного нейрона НС?", "a": ["линейная регрессия", "линейный классификатор", "логистическая регрессия", "решающее дерево глубины 1"], "correct": [0, 1, 2, 3], "explanation": "Один формальный нейрон = сумматор + активация. Тождественная активация даёт линейную регрессию, пороговая — линейный классификатор и пень (решающее дерево глубины 1 = порог по одному признаку), сигмоида — логистическую регрессию."}, {"id": "t7-003", "topic": "t7", "q": "Какую функцию активации используют в последнем слое в (общей) задаче регрессии?", "a": ["сигмоида", "тождественная", "ReLU", "softmax", "ELU", "swish"], "correct": [1], "explanation": "В регрессии выход может быть любым вещественным числом, поэтому используют тождественную (линейную) активацию."}, {"id": "t7-004", "topic": "t7", "q": "Как реализована сигмоида в pytorch?", "a": ["в виде функции torch.nn.functional.sigmoid", "в виде модуля torch.nn.Sigmoid", "передаётся как параметр линейным модулям torch.nn.Linear(activation='sigmoid')", "нет явной реализации"], "correct": [0, 1], "explanation": "Есть и функциональная форма torch.nn.functional.sigmoid (torch.sigmoid), и модуль torch.nn.Sigmoid. Параметра activation у nn.Linear нет."}, {"id": "t7-005", "topic": "t7", "q": "Скольких нейронов с пороговой активацией достаточно для реализации XOR?", "a": ["4", "3", "2", "1"], "correct": [1], "explanation": "XOR не линейно разделим: нужен скрытый слой из 2 нейронов плюс 1 выходной — всего 3 пороговых нейрона."}, {"id": "t7-006", "topic": "t7", "q": "Теорема об универсальной аппроксимации Хорника о...", "a": ["реализации любых функций", "реализации непрерывных функций", "реализации гладких функций", "однослойных сетях", "двухслойных сетях", "глубоких сетях"], "correct": [1, 4], "explanation": "Хорник: сеть с одним скрытым слоем (двухслойная) приближает любую непрерывную функцию на компакте с произвольной точностью."}, {"id": "t7-007", "topic": "t7", "q": "В теореме аппроксимации Пинкуса... (несколько вариантов)", "a": ["полиномиальные активации в 1м слое", "полиномиальные активации везде", "неполиномиальные активации в 1м слое", "тождественные активации во 2м слое", "однослойные сети", "двухслойные сети", "глубокие сети"], "correct": [2, 3, 5], "explanation": "Пинкус: двухслойная сеть с НЕполиномиальной активацией в скрытом слое и тождественной во втором обладает свойством универсальной аппроксимации. Полиномиальная активация это свойство ломает."}, {"id": "t7-008", "topic": "t7", "q": "Что означает черта (подчёркивание) в конце названия метода в pytorch?", "a": ["inplace", "hidden", "private", "forbidden"], "correct": [0], "explanation": "Суффикс «_» означает inplace-операцию: метод изменяет тензор на месте (например add_, zero_)."}, {"id": "t7-009", "topic": "t7", "q": "При реализации softmax(a) на практике применяют приём, в котором...", "a": ["вычитается max(a)", "прибавляется max(a)", "делится на max(a)", "умножается на max(a)", "вычитается mean(a)", "прибавляется mean(a)", "делится на mean(a)", "умножается на mean(a)"], "correct": [0], "explanation": "Для численной устойчивости из аргументов вычитают max(a): значение softmax не меняется, но исчезает риск переполнения exp."}, {"id": "t7-010", "topic": "t7", "q": "При вычислении loss = F.cross_entropy(input, target) тензор input имеет размеры 3×5. Какие размеры у target?", "a": ["3×5", "5×3", "3×3", "5×5", "1", "3", "5", "любые"], "correct": [5], "explanation": "input = (N=3 объекта, C=5 классов). target — это индексы классов длины N, то есть тензор размера 3."}, {"id": "t7-011", "topic": "t7", "q": "Какая сложность нахождения всех мёртвых нейронов (Dead Neurons) от длины выборки m?", "a": ["m", "sqrt(m)", "m²", "m·log(m)", "m²·log(m)", "m³"], "correct": [0], "explanation": "Достаточно одного прохода по всей выборке и проверки, активировался ли нейрон хоть раз — линейная сложность O(m)."}, {"id": "t7-012", "topic": "t7", "q": "Что при обратном распространении градиента передаётся в переменную y гейта сложения (z=x+y)?", "a": ["g", "z·g", "x·g", "y·g", "x", "y", "0"], "correct": [0], "explanation": "∂z/∂y = 1, поэтому гейт сложения просто пропускает входящий градиент g без изменений."}, {"id": "t7-013", "topic": "t7", "q": "Что при обратном распространении градиента передаётся в переменную y гейта умножения (z=x·y)?", "a": ["g", "z·g", "x·g", "y·g", "x", "y", "0"], "correct": [2], "explanation": "∂z/∂y = x, поэтому в y уходит x·g (входящий градиент умножается на значение другого входа)."}, {"id": "t7-014", "topic": "t7", "q": "Что при обратном распространении градиента передаётся в переменную y max-гейта при x>y?", "a": ["g", "z·g", "x·g", "y·g", "x", "y", "0"], "correct": [6], "explanation": "Max-гейт направляет весь градиент только к большему входу. При x>y максимум — это x, значит в y приходит 0."}, {"id": "t7-015", "topic": "t7", "q": "Какие из перечисленных функций активации немонотонные?", "a": ["сигмоида", "тождественная", "ReLU", "swish", "ELU", "GELU"], "correct": [3, 5], "explanation": "Swish и GELU имеют небольшой провал при отрицательных аргументах — они немонотонны. Сигмоида, тождественная, ReLU, ELU монотонны."}, {"id": "t7-016", "topic": "t7", "q": "Пусть x — тензор размера 2×2. Что выдаст x.unsqueeze(dim=1).shape?", "a": ["[2, 2]", "[4]", "[4, 1]", "[1, 4]", "[1, 2, 2]", "[2, 1, 2]", "[2, 2, 1]", "нет верного ответа"], "correct": [5], "explanation": "unsqueeze(dim=1) вставляет ось размера 1 на позицию 1: [2,2] → [2,1,2]."}, {"id": "t7-017", "topic": "t7", "q": "Пусть x — тензор размера 2×2. Что выдаст x.squeeze().shape?", "a": ["[2, 2]", "[4]", "[4, 1]", "[1, 4]", "[1, 2, 2]", "[2, 1, 2]", "[2, 2, 1]", "нет верного ответа"], "correct": [0], "explanation": "squeeze() убирает оси размера 1. В [2,2] таких осей нет, поэтому форма не меняется — [2,2]."}, {"id": "t7-018", "topic": "t7", "q": "Что выдаст код?\nx = torch.Tensor([1, 2, 3])\nw = torch.tensor([1., 1, 1], requires_grad=True)\nz = w @ x\nz.backward()\nprint(x.grad)", "a": ["ошибку", "None", "[1, 2, 3]", "[1, 1, 1]", "[0, 0, 0]", "0"], "correct": [1], "explanation": "У x не выставлен requires_grad (по умолчанию False), поэтому градиент по нему не накапливается — x.grad == None."}, {"id": "t7-019", "topic": "t7", "q": "Строчки кода ниже являются признаком...\nfrom torchvision import models\nresnet18 = models.resnet18(pretrained=True)", "a": ["обучения с учителем", "обучения без учителя", "трансферного обучения", "обучения с масками", "самообучения"], "correct": [2], "explanation": "Загрузка предобученной сети для дальнейшего использования/дообучения — это трансферное обучение."}, {"id": "t7-020", "topic": "t7", "q": "Инициализация Ксавьера (nn.init.xavier_uniform) выведена в предположении...", "a": ["тождественной активации", "однослойности сети", "большой глубины сети", "равномерного распределения сигналов", "отсутствия смещения (bias=False)"], "correct": [0], "explanation": "Вывод Xavier-инициализации опирается на линейный (тождественный) режим активации вблизи нуля, чтобы дисперсия сигналов сохранялась от слоя к слою."}, {"id": "t7-021", "topic": "t7", "q": "Техника Early Stopping применяется (отметьте все верные варианты):", "a": ["при обучении бустинга", "при обучении нейросетей", "при работе сегментаторов", "при отсутствии стоп-токенов"], "correct": [0, 1], "explanation": "Ранняя остановка по контрольной выборке применяется и в градиентном бустинге, и при обучении нейросетей — как способ регуляризации."}, {"id": "t7-022", "topic": "t7", "q": "В каких методах оптимизации градиент вычисляется НЕ в текущей точке?", "a": ["SGD", "momentum", "Нестерова", "Adagrad", "RMSprop", "Adam"], "correct": [2], "explanation": "В методе Нестерова градиент считается в «забегающей вперёд» точке (после применения накопленного импульса)."}, {"id": "t7-023", "topic": "t7", "q": "В каких методах оптимизации шаг делается НЕ строго в сторону текущего градиента?", "a": ["SGD", "momentum", "Нестерова", "Adagrad", "RMSprop", "Adam"], "correct": [1, 2, 3, 4, 5], "explanation": "Только чистый SGD идёт строго против текущего градиента. Импульсные методы добавляют инерцию, а Adagrad/RMSprop/Adam меняют направление за счёт покоординатного масштабирования."}, {"id": "t7-024", "topic": "t7", "q": "В каких методах оптимизации шаг нормируется (градиент делится на что-то)?", "a": ["SGD", "momentum", "Нестерова", "Adagrad", "RMSprop", "Adam"], "correct": [3, 4, 5], "explanation": "Adagrad, RMSprop и Adam делят шаг на (корень из) накопленных квадратов градиентов — это адаптивная покоординатная нормировка."}, {"id": "t7-025", "topic": "t7", "q": "Что означает буква D в названии метода оптимизации Adam?", "a": ["Double", "Descent", "Dummy", "нет верного ответа"], "correct": [3], "explanation": "Adam = ADAptive Moment estimation. Буква D — это часть слова «Adaptive», отдельного значения у неё нет."}, {"id": "t7-026", "topic": "t7", "q": "Где в PyTorch указывается необходимость перемешивания выборки (shuffle=True)?", "a": ["TensorDataset", "DataLoader", "optimizer", "backward", "при инициализации НС", "нет верного ответа"], "correct": [1], "explanation": "Параметр shuffle=True задаётся при создании DataLoader."}, {"id": "t7-027", "topic": "t7", "q": "Где в PyTorch указывается размер батча (batch_size=512)?", "a": ["TensorDataset", "DataLoader", "optimizer", "backward", "при инициализации НС", "нет верного ответа"], "correct": [1], "explanation": "batch_size задаётся при создании DataLoader."}, {"id": "t7-028", "topic": "t7", "q": "Где в коде меняются параметры нейросети?", "a": ["optimizer.zero_grad()", "output = model(input)", "loss = loss_fn(output, target)", "loss.backward()", "optimizer.step()"], "correct": [4], "explanation": "Веса обновляются вызовом optimizer.step() — после того как градиенты посчитаны backward()."}, {"id": "t7-029", "topic": "t7", "q": "Где в коде вычисляются градиенты в вычислительном графе нейросети?", "a": ["optimizer.zero_grad()", "output = model(input)", "loss = loss_fn(output, target)", "loss.backward()", "optimizer.step()"], "correct": [3], "explanation": "Градиенты по всем параметрам вычисляются при вызове loss.backward()."}, {"id": "t7-030", "topic": "t7", "q": "Где используется формула  y = f(W·x) · 1/(1−p) ?", "a": ["Standard Dropout", "Inverted Dropout", "DropConnect", "Gradient clipping", "BatchNorm"], "correct": [1], "explanation": "Масштабирование активаций на 1/(1−p) во время обучения — это Inverted Dropout (на инференсе ничего домножать не нужно)."}, {"id": "t7-031", "topic": "t7", "q": "После какой строки логично делать обрезку градиента (clip_grad_norm)?", "a": ["optimizer.zero_grad()", "output = model(input)", "loss = loss_fn(output, target)", "loss.backward()", "optimizer.step()"], "correct": [3], "explanation": "Обрезку делают после backward() (когда градиенты уже посчитаны), но до optimizer.step()."}, {"id": "t7-032", "topic": "t7", "q": "При обосновании какого метода упоминался эффект Covariate shift (смещения распределений)?", "a": ["Standard Dropout", "Inverted Dropout", "DropConnect", "Gradient clipping", "BatchNorm", "аугментация"], "correct": [4], "explanation": "BatchNorm обосновывался борьбой с «internal covariate shift» — смещением распределений активаций между слоями."}, {"id": "t7-033", "topic": "t7", "q": "Какие слои по-разному работают в режимах train() и eval()?", "a": ["Dropout", "BatchNorm", "ReLU", "Linear", "conv2d", "нет верного ответа"], "correct": [0, 1], "explanation": "Dropout (в eval отключается) и BatchNorm (в eval использует накопленные скользящие статистики) ведут себя по-разному. ReLU, Linear, Conv2d — одинаково."}, {"id": "t7-034", "topic": "t7", "q": "Какой параметр передаётся при инициализации программатора оптимизации torch.optim.lr_scheduler?", "a": ["нейросеть", "параметры нейросети", "градиенты нейросети", "оптимизатор"], "correct": [3], "explanation": "lr_scheduler получает на вход оптимизатор, шаг обучения которого он будет менять."}, {"id": "t7-035", "topic": "t7", "q": "При какой нормировке статистики считаются по указанному региону (см. рисунок)?", "a": ["BatchNorm", "Layer Norm", "Instance Norm", "Group Norm", "Batch renormalization", "нет верного ответа"], "correct": [2], "explanation": "Выделен один канал одного объекта по всем H,W (фиксированы C и N). Усреднение по пространству для каждого канала и каждого объекта — это Instance Norm.", "img": "q35_instancenorm.png"}, {"id": "t7-036", "topic": "t7", "q": "Что делается в Snapshot Ensemble?", "a": ["стекинг нейросетей", "усреднение нейронки и другого метода", "усреднение сетей с разной инициализацией", "усреднение сетей с разными гиперпараметрами", "усреднение сети на разных эпохах"], "correct": [4], "explanation": "Snapshot Ensemble сохраняет состояния ОДНОЙ сети в разных точках обучения (на минимумах циклического lr) и усредняет эти «снимки»."}, {"id": "t7-037", "topic": "t7", "q": "Тензор x имеет размер [1,1,28,28]. Что выведет F.max_pool2d(nn.Conv2d(1,1,kernel_size=3)(x), kernel_size=2).shape?", "a": ["[1, 1, 28, 28]", "[1, 1, 26, 26]", "[1, 1, 14, 14]", "[1, 1, 13, 13]", "[1, 1, 11, 11]", "[1, 1, 5, 5]"], "correct": [3], "explanation": "Свёртка 3×3 без паддинга: 28→26. Max-pool 2×2 (stride 2): 26→13. Итог [1,1,13,13]."}, {"id": "t7-038", "topic": "t7", "q": "Какая сеть считается первой свёрточной?", "a": ["LeNet-5", "AlexNet", "VGG", "GoogLeNet", "ResNet", "нет верного ответа"], "correct": [0], "explanation": "Классической первой свёрточной сетью считается LeNet-5 (LeCun)."}, {"id": "t7-039", "topic": "t7", "q": "В какой сети впервые использовались ReLU и maxpool?", "a": ["LeNet-5", "AlexNet", "VGG", "GoogLeNet", "ResNet", "нет верного ответа"], "correct": [1], "explanation": "Из рассмотренных архитектур ReLU и max-pooling впервые широко применила AlexNet."}, {"id": "t7-040", "topic": "t7", "q": "В какой сети впервые использовались последовательности («каскад») 3×3-свёрток?", "a": ["LeNet-5", "AlexNet", "VGG", "GoogLeNet", "ResNet", "нет верного ответа"], "correct": [2], "explanation": "Каскады маленьких 3×3-свёрток — фирменная идея VGG."}, {"id": "t7-041", "topic": "t7", "q": "В какой сети использовалась модульная архитектура и было всего 5M параметров?", "a": ["LeNet-5", "AlexNet", "VGG", "GoogLeNet", "ResNet", "нет верного ответа"], "correct": [3], "explanation": "GoogLeNet (Inception) построен из повторяющихся модулей и при этом имеет всего ~5 млн параметров."}, {"id": "t7-042", "topic": "t7", "q": "В какой сети впервые использовали BatchNorm и отказались от DropOut?", "a": ["LeNet-5", "AlexNet", "VGG", "GoogLeNet", "ResNet", "нет верного ответа"], "correct": [3], "explanation": "BatchNorm появился в варианте Inception/GoogLeNet (Inception-BN, статья Ioffe & Szegedy), где батч-нормировка позволила отказаться от dropout."}, {"id": "t7-043", "topic": "t7", "q": "Выберите верные утверждения для «Squeeze-and-Excitation» (SE) блока:", "a": ["не меняет размеры тензора", "делает перекалибровку каналов", "использует двухслойную нейросеть", "использует «узкое горло»"], "correct": [0, 1, 2, 3], "explanation": "SE-блок не меняет размер тензора, выполняет поканальную перекалибровку через маленькую двухслойную FC-сеть с понижением размерности («узким горлом»)."}, {"id": "t7-044", "topic": "t7", "q": "Тензор x имеет размер [1,20,30,10]. Что выведет nn.ConvTranspose2d(20,10,kernel_size=2)(x).shape?", "a": ["[20, 10, 29, 9]", "[20, 10, 30, 10]", "[20, 10, 31, 11]", "[1, 10, 29, 9]", "[1, 10, 30, 10]", "[1, 10, 31, 11]"], "correct": [5], "explanation": "ConvTranspose2d (stride 1, pad 0, k=2): пространственный размер растёт на k−1=1, каналы 20→10, батч 1. Итог [1,10,31,11]."}, {"id": "t7-045", "topic": "t7", "q": "Перед какими слоями разумно делать свёртку без смещения (bias=False)?", "a": ["ReLU", "DropOut", "BatchNorm", "maxpool"], "correct": [2], "explanation": "Перед BatchNorm смещение свёртки бесполезно: BN сам вычитает среднее и имеет собственный сдвиг β."}, {"id": "t7-046", "topic": "t7", "q": "Как называется задача, в которой ответ представляется в виде приведённого рисунка (каждый пиксель отнесён к классу)?", "a": ["Локализация", "Семантическая сегментация", "Детектирование объектов", "Сегментация объектов"], "correct": [1], "explanation": "Размечена вся сцена (небо, трава, гора, объект) — каждому пикселю присвоен класс. Это семантическая сегментация.", "img": "q46_semantic.png"}, {"id": "t7-047", "topic": "t7", "q": "Подсчитайте IoU для прямоугольников на рисунке.", "a": ["0", "1/4", "1/3", "1/2", "2/3", "3/4", "нет верного ответа"], "correct": [2], "explanation": "Площади прямоугольников по 2, пересечение 1×1=1, объединение 2+2−1=3. IoU = 1/3.", "img": "q47_iou.png"}, {"id": "t7-048", "topic": "t7", "q": "Вычислите Average Precision (AP) для указанного случая (один класс, ответ округлить до десятых).", "a": ["0.5", "0.6", "0.7", "0.8", "нет верного ответа"], "correct": [4], "explanation": "Сортируя по уверенности (0.9 TP, 0.8 TP, 0.7 FP, 0.6 TP) при 3 объектах: AP ≈ (1+1+0.75)/3 ≈ 0.92 → ≈0.9, чего нет среди вариантов. Поэтому «нет верного ответа».", "img": "q48_ap.png"}, {"id": "t7-049", "topic": "t7", "q": "Выберите верные утверждения для R-CNN:", "a": ["использовался Selective Search", "использовался SVM", "использовалась bounding-box-регрессия", "использовался ROI Pooling слой", "использовалась Region Proposal сеть (RPN)"], "correct": [0, 1, 2], "explanation": "R-CNN: регионы от Selective Search, классификация SVM, уточнение рамок bbox-регрессией. ROI Pooling — в Fast R-CNN, RPN — в Faster R-CNN."}, {"id": "t7-050", "topic": "t7", "q": "Для чего нужна процедура NMS (Non Maximum Suppression)?", "a": ["для сокращения числа регионов", "для уменьшения числа классов в ответе", "для уменьшения числа параметров сети", "для уменьшения уверенности в регионах-ответах"], "correct": [0], "explanation": "NMS убирает дублирующие перекрывающиеся рамки, оставляя для объекта одну с максимальной уверенностью — сокращает число регионов-ответов."}, {"id": "t7-051", "topic": "t7", "q": "Тензор имеет размеры 10×100×100 (10 каналов). Какой размер у ответа Spatial Pyramid Pooling слоя (см. рис.)?", "a": ["10", "4", "16", "32", "160", "200", "210", "1600", "нет верного ответа"], "correct": [6], "explanation": "Уровни пирамиды 4×4, 2×2, 1×1 дают 16+4+1=21 ячейку на канал. 21×10 каналов = 210.", "img": "q51_spp.png"}, {"id": "t7-052", "topic": "t7", "q": "Тензор имеет размеры 10×100×100 (10 каналов). Какой размер будет после ROI Pooling слоя с сеткой 5×5 (см. рис.)?", "a": ["10", "25", "5×5", "5×10", "100×100", "1×5×5", "10×5×5", "10×100×100", "нет верного ответа"], "correct": [6], "explanation": "ROI Pooling приводит регион к фиксированной сетке, сохраняя число каналов: 10×5×5.", "img": "q52_roipool.png"}, {"id": "t7-053", "topic": "t7", "q": "Выберите верные утверждения для Fast R-CNN:", "a": ["использовался Selective Search", "использовался SVM", "использовалась bounding-box-регрессия", "использовался ROI Pooling слой", "использовалась Region Proposal сеть (RPN)"], "correct": [0, 2, 3], "explanation": "Fast R-CNN: регионы по-прежнему от Selective Search, появился ROI Pooling и общий backbone, классификация уже softmax (SVM убрали), bbox-регрессия есть. RPN — только в Faster R-CNN."}, {"id": "t7-054", "topic": "t7", "q": "Выберите верные утверждения для Faster R-CNN:", "a": ["использовался Selective Search", "использовался SVM", "использовалась bounding-box-регрессия", "использовался ROI Pooling слой", "использовалась Region Proposal сеть (RPN)"], "correct": [2, 3, 4], "explanation": "Faster R-CNN заменил Selective Search обучаемой RPN, сохранил ROI Pooling и bbox-регрессию; SVM не используется."}, {"id": "t7-055", "topic": "t7", "q": "Сеть YOLO строится для сетки 2×2, 10 классов, 2 региона (бокса) на ячейку. Сколько элементов в выходном тензоре?", "a": ["4", "10", "20", "40", "80", "нет верного ответа"], "correct": [4], "explanation": "Размер выхода = S·S·(B·5 + C) = 2·2·(2·5 + 10) = 4·20 = 80."}, {"id": "t7-056", "topic": "t7", "q": "Из статьи про какую сеть эта иллюстрация (8×8 feature map с дефолтными боксами)?", "a": ["R-CNN", "Fast R-CNN", "YOLO", "SSD", "нет верного ответа"], "correct": [3], "explanation": "Несколько карт признаков разного масштаба (8×8, 4×4) с набором дефолтных боксов в каждой ячейке — это SSD.", "img": "q56_ssd.png"}, {"id": "t7-057", "topic": "t7", "q": "Выберите верные утверждения для CornerNet:", "a": ["безъякорная сеть", "использовался особый вид пулинга", "использовалась Region Proposal сеть (RPN)"], "correct": [0, 1], "explanation": "CornerNet — anchor-free сеть, детектирует углы рамки и использует особый corner pooling. RPN в ней нет."}, {"id": "t7-058", "topic": "t7", "q": "В SSD на масштабе (тензоре) 3×3×256 используется 3 якоря, 10 классов. Какой размер тензора КЛАССИФИКАЦИИ на этом масштабе?", "a": ["3×10", "3×11", "3×30", "3×33", "3×3×10", "3×3×11", "3×3×30", "3×3×31", "3×3×33", "нет верного ответа"], "correct": [6], "explanation": "На каждую из 3×3 позиций — 3 якоря × 10 классов = 30 каналов. Тензор классификации 3×3×30.", "img": "q56_ssd.png"}, {"id": "t7-059", "topic": "t7", "q": "В SSD на масштабе (тензоре) 3×3×256 используется 3 якоря, 10 классов. Какой размер тензора BB-РЕГРЕССИИ на этом масштабе?", "a": ["3×10", "3×11", "3×12", "3×3×10", "3×3×11", "3×3×12", "3×3×33", "нет верного ответа"], "correct": [5], "explanation": "На каждую позицию 3×3 — 3 якоря × 4 координаты = 12 каналов. Тензор регрессии 3×3×12."}, {"id": "t7-060", "topic": "t7", "q": "Какой архитектуре соответствует рисунок «(b) Single feature map»?", "a": ["R-CNN", "Fast R-CNN", "YOLO", "SSD", "FPN", "U-net"], "correct": [2], "explanation": "Предсказание делается с одной (верхней) карты признаков — так устроен YOLO (предсказание с единственной карты признаков).", "img": "q60_single_fmap.png"}, {"id": "t7-061", "topic": "t7", "q": "Какой архитектуре соответствует рисунок «(c) Pyramidal feature hierarchy»?", "a": ["R-CNN", "Fast R-CNN", "YOLO", "SSD", "FPN", "U-net"], "correct": [3], "explanation": "Предсказания делаются независимо на нескольких уровнях свёрточной пирамиды признаков — это SSD.", "img": "q61_pyramidal.png"}, {"id": "t7-062", "topic": "t7", "q": "Какой архитектуре соответствует рисунок «(e) Similar Structure with (d)» (нисходящий путь, предсказание только на самом мелком уровне)?", "a": ["R-CNN", "Fast R-CNN", "YOLO", "SSD", "FPN", "U-net"], "correct": [5], "explanation": "Кодер-декодер с нисходящим путём и боковыми связями, но с единственным выходом на самом высоком разрешении — это структура U-net.", "img": "q62_similar_d.png"}, {"id": "t7-063", "topic": "t7", "q": "В FCOS два целевых региона пересекаются. Для точки в пересечении какой регион считается целевым?", "a": ["оба", "новый регион — пересечение", "случайный", "наибольший", "наименьший", "никакой"], "correct": [4], "explanation": "В FCOS при неоднозначности точке назначается рамка наименьшей площади."}, {"id": "t7-064", "topic": "t7", "q": "Из статьи про какую сеть эта иллюстрация (точка и расстояния l*, t*, r*, b* до сторон рамки)?", "a": ["R-CNN", "Fast R-CNN", "YOLO", "SSD", "CornerNet", "FCOS", "нет верного ответа"], "correct": [5], "explanation": "Регрессия из каждой точки четырёх расстояний до сторон рамки (l*, t*, r*, b*) и центральность — это FCOS.", "img": "q64_fcos.png"}, {"id": "t7-065", "topic": "t7", "q": "Какой размер выходного тензора-регрессии FCOS на масштабе 100×100?", "a": ["10×10×2", "10×10×4", "100×100", "100×100×2", "100×100×4", "нет верного ответа"], "correct": [4], "explanation": "FCOS в каждой точке регрессирует 4 числа (l,t,r,b): 100×100×4."}, {"id": "t7-066", "topic": "t7", "q": "Что использовалось в указанных сетях?", "a": ["«обратный» пулинг (unpooling) в SegNet", "«расширенные» (dilated) свёртки в DeepLab", "RPN в YOLO"], "correct": [0, 1], "explanation": "SegNet использует unpooling по сохранённым индексам, DeepLab — dilated/atrous свёртки. В YOLO нет RPN."}, {"id": "t7-067", "topic": "t7", "q": "Из статьи про какую сеть эта иллюстрация (параллельные потоки разного разрешения с обменом)?", "a": ["SegNet", "Unet", "DeepLab", "PSP-Net", "SharpMask", "HR-Representations", "нет верного ответа"], "correct": [5], "explanation": "Несколько ветвей разного разрешения, идущих параллельно с постоянным обменом информацией, — это HRNet (High-Resolution Representations).", "img": "q67_hrnet.png"}, {"id": "t7-068", "topic": "t7", "q": "Что делалось в Unet (оригинальная работа)?", "a": ["вырезание подтензоров (crop)", "конкатенация после прокидывания связи", "«обратный» пулинг (unpooling)", "3×3-свёртки"], "correct": [0, 1, 3], "explanation": "U-net: из-за свёрток без паддинга карты обрезаются (crop) перед конкатенацией по skip-связи; используются 3×3-свёртки. Апсемплинг делается up-convolution, а не unpooling (это в SegNet)."}, {"id": "t7-069", "topic": "t7", "q": "Что верно для Mask R-CNN?", "a": ["заменили RoIPool на RoIAlign", "добавили «обратный» пулинг", "добавили 3×3-свёртки в ветку масок", "фактически сеть решает 3 задачи CV (ошибка равна сумме трёх)"], "correct": [0, 2, 3], "explanation": "Mask R-CNN заменил RoIPool на RoIAlign, добавил свёрточную ветку масок (FCN с 3×3-свёртками) и решает три задачи: классификация + регрессия рамок + маска (суммарный loss)."}, {"id": "t7-070", "topic": "t7", "q": "Из статьи про какую сеть эта иллюстрация (лучи из центра объекта до контура)?", "a": ["Mask R-CNN", "TensorMask", "YOLO", "PolarMask", "CornerNet", "FCOS", "нет верного ответа"], "correct": [3], "explanation": "Маска задаётся в полярных координатах — длинами лучей из центра до контура. Это PolarMask.", "img": "q70_polarmask.png"}, {"id": "t7-071", "topic": "t7", "q": "Какой размер выходного тензора Mask-регрессии у PolarMask на масштабе 100×100, 10 классах, 8 лучах?", "a": ["10×4", "10×8", "10×16", "100×100×4", "100×100×8", "100×100×10", "100×100×16", "нет верного ответа"], "correct": [4], "explanation": "PolarMask регрессирует длины лучей (маска класс-агностична): в каждой точке 8 чисел → 100×100×8."}, {"id": "t7-072", "topic": "t7", "q": "Из статьи про какую концепцию эта иллюстрация (граф со случайными связями)?", "a": ["LSTM", "peephole connections", "резервуарные вычисления", "динамический dropout", "нет верного ответа"], "correct": [2], "explanation": "Случайный фиксированный «резервуар» нейронов, где обучается только выход, — это резервуарные вычисления (echo state / reservoir computing).", "img": "q72_reservoir.png"}, {"id": "t7-073", "topic": "t7", "q": "Из статьи про какую концепцию эта иллюстрация (одинаковые dropout-маски, повторяющиеся по шагам времени)?", "a": ["многослойные LSTM", "peephole connections", "variational dropout", "языковые модели", "нет верного ответа"], "correct": [2], "explanation": "Одна и та же маска dropout применяется на всех временных шагах (показана цветом) — это variational dropout для RNN.", "img": "q73_vardropout.png"}, {"id": "t7-074", "topic": "t7", "q": "В какой ячейке меньше гейтов?", "a": ["LSTM", "LSTM with peephole connections", "GRU"], "correct": [2], "explanation": "У GRU два гейта (сброса и обновления), у LSTM — три. Значит у GRU меньше."}, {"id": "t7-075", "topic": "t7", "q": "В приведённом коде какой размер у hidden?\nlstm = nn.LSTM(input_size=3, hidden_size=3, num_layers=1, bias=True, batch_first=False, bidirectional=False)\nout, hidden = lstm(input, hidden)", "a": ["1×1×3", "1×1×6", "[1×1×3, 1×1×3]", "[1×1×6, 1×1×6]", "[1×1×3, 1×1×3, 1×1×3]", "нет верного ответа"], "correct": [2], "explanation": "hidden — это кортеж (h_n, c_n); каждый тензор имеет форму (num_layers·num_directions, batch, hidden_size) = 1×1×3. Итого [1×1×3, 1×1×3]."}, {"id": "t7-076", "topic": "t7", "q": "Какие активации используются в LSTM-ячейке?", "a": ["сигмоида", "гиперболический тангенс", "ReLU", "softmax", "ELU"], "correct": [0, 1], "explanation": "Гейты LSTM используют сигмоиду, а кандидат и выход состояния — гиперболический тангенс."}, {"id": "t7-077", "topic": "t7", "q": "Какие активации используются в GRU-ячейке?", "a": ["сигмоида", "гиперболический тангенс", "ReLU", "softmax", "ELU"], "correct": [0, 1], "explanation": "В GRU гейты — сигмоида, кандидат скрытого состояния — гиперболический тангенс."}, {"id": "t7-078", "topic": "t7", "q": "В каком подходе используется дискриминатор?", "a": ["teacher forcing", "professor forcing", "free running", "scheduled sampling", "нет верного ответа"], "correct": [1], "explanation": "Professor forcing использует дискриминатор (как в GAN), чтобы сблизить распределения скрытых состояний при обучении с учителем и в свободном прогоне."}, {"id": "t7-079", "topic": "t7", "q": "Что из перечисленного может использоваться в RNN?", "a": ["BN (BatchNorm)", "DO (Dropout)", "grad clipping", "teacher forcing"], "correct": [1, 2, 3], "explanation": "В RNN типично применяют dropout (вариационный), обрезку градиента (борьба со взрывом) и teacher forcing. Обычный BatchNorm вдоль времени плохо подходит."}, {"id": "t7-080", "topic": "t7", "q": "Что в аббревиатуре TBPTT (для RNN) обозначает первая буква T?", "a": ["tensor", "test", "time", "tick", "truncated", "нет верного ответа"], "correct": [4], "explanation": "TBPTT = Truncated BackPropagation Through Time — усечённое обратное распространение во времени."}, {"id": "t7-081", "topic": "t7", "q": "Что из перечисленного верно для ELMo?", "a": ["предтренировка без учителя", "представление слова = линейная комбинация скрытых состояний", "двунаправленная языковая модель (biLM)", "не учитывает контекст слова"], "correct": [0, 1, 2], "explanation": "ELMo предобучается без разметки как двунаправленная языковая модель; итоговое представление — линейная комбинация скрытых состояний и зависит от контекста (последний пункт неверен)."}, {"id": "t7-082", "topic": "t7", "q": "В каком из этих представлений производится разложение матрицы логарифмов частот (совстречаемости)?", "a": ["w2v", "fasttext", "GloVe", "ELMo"], "correct": [2], "explanation": "GloVe строится как факторизация матрицы логарифмов частот совместной встречаемости слов."}, {"id": "t7-083", "topic": "t7", "q": "В каком из этих представлений представление слова равно сумме представлений n-грамм?", "a": ["w2v", "fasttext", "GloVe", "ELMo"], "correct": [1], "explanation": "fastText представляет слово как сумму эмбеддингов его символьных n-грамм."}, {"id": "t7-084", "topic": "t7", "q": "Что верно для (или используется в) word2vec?", "a": ["учитывается контекст слова", "Negative Sampling", "Hierarchical Softmax", "нужна размеченная выборка текстов"], "correct": [0, 1, 2], "explanation": "word2vec обучается на контексте (CBOW/skip-gram) с ускорениями Negative Sampling или Hierarchical Softmax; разметка не нужна — обучение самоконтролируемое."}, {"id": "t7-085", "topic": "t7", "q": "Что означает буква C в аббревиатуре CBOW?", "a": ["count", "continuous", "circle", "нет верного ответа"], "correct": [1], "explanation": "CBOW = Continuous Bag-of-Words. C — Continuous."}]};
